273→func TestHandleLifecycleCompaction_ResetsTranscriptOffset(t *testing.T) {
274→	// Cannot use t.Parallel() because we use t.Chdir()
275→	tmpDir := t.TempDir()
276→	t.Chdir(tmpDir)
277→
278→	// Initialize git repo with a commit (not empty)
279→	setupGitRepoWithCommit(t, tmpDir)
280→	paths.ClearRepoRootCache()
281→
282→	// Create .entire directory structure
283→	if err := os.MkdirAll(paths.EntireDir, 0o755); err != nil {
284→		t.Fatalf("Failed to create .entire: %v", err)
285→	}
286→
287→	// Create a transcript file
288→	transcriptPath := filepath.Join(tmpDir, "transcript.jsonl")
289→	transcriptContent := `{"type":"user","message":{"role":"user","content":"test prompt"}}` + "\n"
290→	if err := os.WriteFile(transcriptPath, []byte(transcriptContent), 0o644); err != nil {
291→		t.Fatalf("Failed to create transcript: %v", err)
292→	}
293→
294→	sessionID := "compaction-test-session"
295→
296→	// Create session state with non-zero transcript offset
297→	sessionState := &strategy.SessionState{
298→		SessionID:                 sessionID,
299→		CheckpointTranscriptStart: 50, // Non-zero offset to be reset
300→	}
301→	if err := strategy.SaveSessionState(sessionState); err != nil {
302→		t.Fatalf("Failed to save session state: %v", err)
303→	}
304→
305→	ag := newMockAgent()
306→	event := &agent.Event{
307→		Type:       agent.Compaction,
308→		SessionID:  sessionID,
309→		SessionRef: transcriptPath,
310→	}
311→
312→	// handleLifecycleCompaction resets the transcript offset regardless of other operations.
313→	// It fires EventCompaction which stays in ACTIVE phase and resets CheckpointTranscriptStart.
314→	err := handleLifecycleCompaction(ag, event)
315→	if err != nil {
316→		t.Logf("handleLifecycleCompaction returned error (expected in minimal test): %v", err)
317→	}
318→
319→	// Verify CheckpointTranscriptStart was reset to 0
320→	loadedState, loadErr := strategy.LoadSessionState(sessionID)
321→	if loadErr != nil {
322→		t.Fatalf("Failed to load session state after compaction: %v", loadErr)
323→	}
324→	if loadedState == nil {
325→		t.Fatal("Session state is nil after compaction")
326→	}
327→	if loadedState.CheckpointTranscriptStart != 0 {
328→		t.Errorf("CheckpointTranscriptStart = %d, want 0 (should be reset on compaction)",
329→			loadedState.CheckpointTranscriptStart)
330→	}
