 34→// ParseHookEvent translates a Claude Code hook into a normalized lifecycle Event.
 35→// Returns nil if the hook has no lifecycle significance.
 36→func (c *ClaudeCodeAgent) ParseHookEvent(hookName string, stdin io.Reader) (*agent.Event, error) {
 37→	switch hookName {
 38→	case HookNameSessionStart:
 39→		return c.parseSessionStart(stdin)
 40→	case HookNameUserPromptSubmit:
 41→		return c.parseTurnStart(stdin)
 42→	case HookNameStop:
 43→		return c.parseTurnEnd(stdin)
 44→	case HookNameSessionEnd:
 45→		return c.parseSessionEnd(stdin)
 46→	case HookNamePreTask:
 47→		return c.parseSubagentStart(stdin)
 48→	case HookNamePostTask:
 49→		return c.parseSubagentEnd(stdin)
 50→	case HookNamePostTodo:
 51→		// PostTodo is Claude-specific; handled outside the generic dispatcher.
 52→		return nil, nil //nolint:nilnil // nil event = no lifecycle action
 53→	default:
 54→		return nil, nil //nolint:nilnil // Unknown hooks have no lifecycle action
 55→	}
 56→}
