 58→// ReadTranscript reads the raw JSONL transcript bytes for a session.
 59→func (c *ClaudeCodeAgent) ReadTranscript(sessionRef string) ([]byte, error) {
 60→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path comes from agent hook input
 61→	if err != nil {
 62→		return nil, fmt.Errorf("failed to read transcript: %w", err)
 63→	}
 64→	return data, nil
 65→}
 66→
 67→// ExtractPrompts extracts user prompts from the transcript starting at the given line offset.
 68→func (c *ClaudeCodeAgent) ExtractPrompts(sessionRef string, fromOffset int) ([]string, error) {
 69→	lines, _, err := transcript.ParseFromFileAtLine(sessionRef, fromOffset)
 70→	if err != nil {
 71→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
 72→	}
 73→
 74→	var prompts []string
 75→	for i := range lines {
 76→		if lines[i].Type != transcript.TypeUser {
 77→			continue
 78→		}
 79→		content := transcript.ExtractUserContent(lines[i].Message)
 80→		if content != "" {
 81→			prompts = append(prompts, textutil.StripIDEContextTags(content))
 82→		}
 83→	}
 84→	return prompts, nil
 85→}
 86→
 87→// ExtractSummary extracts the last assistant message as a session summary.
 88→func (c *ClaudeCodeAgent) ExtractSummary(sessionRef string) (string, error) {
 89→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path comes from agent hook input
 90→	if err != nil {
 91→		return "", fmt.Errorf("failed to read transcript: %w", err)
 92→	}
 93→
 94→	lines, parseErr := transcript.ParseFromBytes(data)
 95→	if parseErr != nil {
 96→		return "", fmt.Errorf("failed to parse transcript: %w", parseErr)
 97→	}
 98→
 99→	// Walk backward to find last assistant text block
100→	for i := len(lines) - 1; i >= 0; i-- {
101→		if lines[i].Type != transcript.TypeAssistant {
102→			continue
103→		}
104→		var msg transcript.AssistantMessage
105→		if err := json.Unmarshal(lines[i].Message, &msg); err != nil {
106→			continue
107→		}
108→		for _, block := range msg.Content {
109→			if block.Type == transcript.ContentTypeText && block.Text != "" {
110→				return block.Text, nil
111→			}
112→		}
113→	}
114→	return "", nil
115→}
