222→// readAndParse reads stdin and unmarshals JSON into the given type.
223→func readAndParse[T any](stdin io.Reader) (*T, error) {
224→	data, err := io.ReadAll(stdin)
225→	if err != nil {
226→		return nil, fmt.Errorf("failed to read hook input: %w", err)
227→	}
228→	if len(data) == 0 {
229→		return nil, errors.New("empty hook input")
230→	}
231→	var result T
232→	if err := json.Unmarshal(data, &result); err != nil {
233→		return nil, fmt.Errorf("failed to parse hook input: %w", err)
234→	}
235→	return &result, nil
236→}
