 41→		HookNameAfterModel, HookNameBeforeToolSelection, HookNameNotification:
 42→		// Acknowledged hooks with no lifecycle action
 43→		return nil, nil //nolint:nilnil // nil event = no lifecycle action
 44→	default:
 45→		return nil, nil //nolint:nilnil // Unknown hooks have no lifecycle action
 46→	}
