 65→	t, parseErr := ParseTranscript(data)
 66→	if parseErr != nil {
 67→		return nil, fmt.Errorf("failed to parse transcript: %w", parseErr)
 68→	}
 69→
 70→	var prompts []string
 71→	for i := fromOffset; i < len(t.Messages); i++ {
 72→		msg := t.Messages[i]
 73→		if msg.Type == MessageTypeUser && msg.Content != "" {
 74→			prompts = append(prompts, msg.Content)
 75→		}
 76→	}
 77→	return prompts, nil
 78→}
 79→
 80→// ExtractSummary extracts the last assistant message as a session summary.
 81→func (g *GeminiCLIAgent) ExtractSummary(sessionRef string) (string, error) {
 82→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path comes from agent hook input
 83→	if err != nil {
 84→		return "", fmt.Errorf("failed to read transcript: %w", err)
 85→	}
 86→	return ExtractLastAssistantMessage(data)
 87→}
 88→
 89→// CalculateTokenUsage computes token usage from the transcript starting at the given message offset.
 90→func (g *GeminiCLIAgent) CalculateTokenUsage(sessionRef string, fromOffset int) (*agent.TokenUsage, error) {
 91→	return CalculateTokenUsageFromFile(sessionRef, fromOffset)
 92→}
