  1→package agent
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"sort"
  7→	"strings"
  8→)
  9→
 10→const (
 11→	// MaxChunkSize is the maximum size for a single transcript chunk.
 12→	// GitHub has a 100MB limit per blob, so we use 50MB to be safe.
 13→	MaxChunkSize = 50 * 1024 * 1024 // 50MB
 14→
 15→	// ChunkSuffix is the format for chunk file suffixes (e.g., ".001", ".002")
 16→	ChunkSuffix = ".%03d"
 17→)
 18→
 19→// ChunkTranscript splits a transcript into chunks using the appropriate agent.
 20→// If agentType is empty or the agent is not found, falls back to JSONL (line-based) chunking.
 21→func ChunkTranscript(content []byte, agentType AgentType) ([][]byte, error) {
 22→	if len(content) <= MaxChunkSize {
 23→		return [][]byte{content}, nil
 24→	}
 25→
 26→	// Try to get the agent by type and use its format-aware chunking
 27→	if agentType != "" {
 28→		ag, err := GetByAgentType(agentType)
 29→		if err == nil {
 30→			chunks, chunkErr := ag.ChunkTranscript(content, MaxChunkSize)
 31→			if chunkErr != nil {
 32→				return nil, fmt.Errorf("agent chunking failed: %w", chunkErr)
 33→			}
 34→			return chunks, nil
 35→		}
 36→	}
 37→
 38→	// Fall back to JSONL chunking (default)
 39→	return ChunkJSONL(content, MaxChunkSize)
 40→}
 41→
 42→// ReassembleTranscript combines chunks back into a single transcript.
 43→// If agentType is empty or the agent is not found, falls back to JSONL (line-based) reassembly.
 44→func ReassembleTranscript(chunks [][]byte, agentType AgentType) ([]byte, error) {
 45→	if len(chunks) == 0 {
 46→		return nil, nil
 47→	}
 48→	if len(chunks) == 1 {
 49→		return chunks[0], nil
 50→	}
 51→
 52→	// Try to get the agent by type and use its format-aware reassembly
 53→	if agentType != "" {
 54→		ag, err := GetByAgentType(agentType)
 55→		if err == nil {
 56→			result, reassembleErr := ag.ReassembleTranscript(chunks)
 57→			if reassembleErr != nil {
 58→				return nil, fmt.Errorf("agent reassembly failed: %w", reassembleErr)
 59→			}
 60→			return result, nil
 61→		}
 62→	}
 63→
 64→	// Fall back to JSONL reassembly (default)
 65→	return ReassembleJSONL(chunks), nil
 66→}
 67→
 68→// ChunkJSONL splits JSONL content at line boundaries.
 69→// This is the default chunking for agents using JSONL format (like Claude Code).
 70→func ChunkJSONL(content []byte, maxSize int) ([][]byte, error) {
 71→	// Handle empty content
 72→	if len(content) == 0 {
 73→		return [][]byte{}, nil
 74→	}
 75→
 76→	lines := strings.Split(string(content), "\n")
 77→	var chunks [][]byte
 78→	var currentChunk strings.Builder
 79→
 80→	for i, line := range lines {
 81→		// Check if adding this line would exceed the chunk size
 82→		lineWithNewline := line + "\n"
 83→
 84→		// Check if a single line exceeds maxSize - this is an error since we can't split JSONL lines
 85→		if len(lineWithNewline) > maxSize {
 86→			return nil, fmt.Errorf("JSONL line %d exceeds maximum chunk size (%d bytes > %d bytes); cannot split a single JSON object", i+1, len(lineWithNewline), maxSize)
 87→		}
 88→
 89→		if currentChunk.Len()+len(lineWithNewline) > maxSize && currentChunk.Len() > 0 {
 90→			// Save current chunk and start a new one
 91→			chunks = append(chunks, []byte(strings.TrimSuffix(currentChunk.String(), "\n")))
 92→			currentChunk.Reset()
 93→		}
 94→		currentChunk.WriteString(lineWithNewline)
 95→	}
 96→
 97→	// Add the last chunk if it has content
 98→	if currentChunk.Len() > 0 {
 99→		chunks = append(chunks, []byte(strings.TrimSuffix(currentChunk.String(), "\n")))
100→	}
101→
102→	return chunks, nil
103→}
104→
105→// ReassembleJSONL concatenates JSONL chunks with newlines.
106→func ReassembleJSONL(chunks [][]byte) []byte {
107→	var result strings.Builder
108→	for i, chunk := range chunks {
109→		result.Write(chunk)
110→		if i < len(chunks)-1 {
111→			result.WriteString("\n")
112→		}
113→	}
114→	return []byte(result.String())
115→}
116→
117→// ChunkFileName returns the filename for a chunk at the given index.
118→// Index 0 returns the base filename, index 1+ returns with chunk suffix.
119→func ChunkFileName(baseName string, index int) string {
120→	if index == 0 {
121→		return baseName
122→	}
123→	return baseName + fmt.Sprintf(ChunkSuffix, index)
124→}
125→
126→// ParseChunkIndex extracts the chunk index from a filename.
127→// Returns 0 for the base file (no suffix), or the chunk number for suffixed files.
128→// Returns -1 if the filename doesn't match the expected pattern.
129→func ParseChunkIndex(filename, baseName string) int {
130→	if filename == baseName {
131→		return 0
132→	}
133→
134→	if !strings.HasPrefix(filename, baseName+".") {
135→		return -1
136→	}
137→
138→	suffix := strings.TrimPrefix(filename, baseName+".")
139→	var index int
140→	if _, err := fmt.Sscanf(suffix, "%03d", &index); err != nil {
141→		return -1
142→	}
143→	return index
144→}
145→
146→// SortChunkFiles sorts chunk filenames in order (base file first, then numbered chunks).
147→func SortChunkFiles(files []string, baseName string) []string {
148→	sorted := make([]string, len(files))
149→	copy(sorted, files)
150→
151→	sort.Slice(sorted, func(i, j int) bool {
152→		idxI := ParseChunkIndex(sorted[i], baseName)
153→		idxJ := ParseChunkIndex(sorted[j], baseName)
154→		return idxI < idxJ
155→	})
156→
157→	return sorted
158→}
159→
160→// geminiTranscriptDetect is used for detecting Gemini JSON format.
161→type geminiTranscriptDetect struct {
162→	Messages []interface{} `json:"messages"`
163→}
164→
165→// DetectAgentTypeFromContent detects the agent type from transcript content.
166→// Returns AgentTypeGemini if it appears to be Gemini JSON format, empty AgentType otherwise.
167→// This is used when the agent type is unknown but we need to chunk/reassemble correctly.
168→func DetectAgentTypeFromContent(content []byte) AgentType {
169→	// Quick check: Gemini JSON starts with { and has a messages array
170→	trimmed := strings.TrimSpace(string(content))
171→	if !strings.HasPrefix(trimmed, "{") {
172→		return ""
173→	}
174→
175→	// Try to parse as Gemini JSON format (object with messages array)
176→	var transcript geminiTranscriptDetect
177→	if err := json.Unmarshal(content, &transcript); err != nil {
178→		return ""
179→	}
180→
181→	// Must have at least one message to be considered Gemini format
182→	if len(transcript.Messages) > 0 {
183→		return AgentTypeGemini
184→	}
185→
186→	return ""
187→}
