  34→// errStop is a sentinel error used to break out of git log iteration.
  35→// Shared across strategies that iterate through git commits.
  36→// NOTE: A similar sentinel exists in checkpoint/temporary.go - this is intentional.
  37→// Each package needs its own package-scoped sentinel for git log iteration patterns.
  38→var errStop = errors.New("stop iteration")
  39→
  40→// IsEmptyRepository returns true if the repository has no commits yet.
  41→// After git-init, HEAD points to an unborn branch (e.g., refs/heads/main)
  42→// whose target does not yet exist. repo.Head() returns ErrReferenceNotFound
  43→// in this case.
  44→func IsEmptyRepository(repo *git.Repository) bool {
  45→	_, err := repo.Head()
  46→	return errors.Is(err, plumbing.ErrReferenceNotFound)
  47→}
  48→
  49→// IsAncestorOf checks if commit is an ancestor of (or equal to) target.
  50→// Returns true if target can reach commit by following parent links.
  51→// Limits search to 1000 commits to avoid excessive traversal.
  52→func IsAncestorOf(repo *git.Repository, commit, target plumbing.Hash) bool {
  53→	if commit == target {
  54→		return true
  55→	}
  56→
  57→	iter, err := repo.Log(&git.LogOptions{From: target})
  58→	if err != nil {
  59→		return false
  60→	}
  61→	defer iter.Close()
  62→
  63→	found := false
  64→	count := 0
  65→	_ = iter.ForEach(func(c *object.Commit) error { //nolint:errcheck // Best-effort search, errors are non-fatal
  66→		count++
  67→		if count > 1000 {
  68→			return errStop
  69→		}
  70→		if c.Hash == commit {
  71→			found = true
  72→			return errStop
  73→		}
  74→		return nil
  75→	})
  76→
  77→	return found
  78→}
