  80→// ListCheckpoints returns all checkpoints from the entire/checkpoints/v1 branch.
  81→// Scans sharded paths: <id[:2]>/<id[2:]>/ directories containing metadata.json.
  82→// Used by both manual-commit and auto-commit strategies.
  83→func ListCheckpoints() ([]CheckpointInfo, error) {
  84→	repo, err := OpenRepository()
  85→	if err != nil {
  86→		return nil, fmt.Errorf("failed to open git repository: %w", err)
  87→	}
  88→
  89→	refName := plumbing.NewBranchReferenceName(paths.MetadataBranchName)
  90→	ref, err := repo.Reference(refName, true)
  91→	if err != nil {
  92→		//nolint:nilerr // No sessions branch yet is expected, return empty list
  93→		return []CheckpointInfo{}, nil
  94→	}
  95→
  96→	commit, err := repo.CommitObject(ref.Hash())
  97→	if err != nil {
  98→		return nil, fmt.Errorf("failed to get commit object: %w", err)
  99→	}
 100→
 101→	tree, err := commit.Tree()
 102→	if err != nil {
 103→		return nil, fmt.Errorf("failed to get commit tree: %w", err)
 104→	}
 105→
 106→	var checkpoints []CheckpointInfo
 107→
 108→	// Scan sharded structure: <2-char-prefix>/<remaining-id>/metadata.json
 109→	// The tree has 2-character directories (hex buckets)
 110→	for _, bucketEntry := range tree.Entries {
 111→		if bucketEntry.Mode != filemode.Dir {
 112→			continue
 113→		}
 114→		// Bucket should be 2 hex chars
 115→		if len(bucketEntry.Name) != 2 {
 116→			continue
 117→		}
 118→
 119→		bucketTree, treeErr := repo.TreeObject(bucketEntry.Hash)
 120→		if treeErr != nil {
 121→			continue
 122→		}
 123→
 124→		// Each entry in the bucket is the remaining part of the checkpoint ID
 125→		for _, checkpointEntry := range bucketTree.Entries {
 126→			if checkpointEntry.Mode != filemode.Dir {
 127→				continue
 128→			}
 129→
 130→			checkpointTree, cpTreeErr := repo.TreeObject(checkpointEntry.Hash)
 131→			if cpTreeErr != nil {
 132→				continue
 133→			}
 134→
 135→			// Reconstruct checkpoint ID: <bucket><remaining>
 136→			checkpointIDStr := bucketEntry.Name + checkpointEntry.Name
 137→			checkpointID, cpErr := id.NewCheckpointID(checkpointIDStr)
 138→			if cpErr != nil {
 139→				// Skip invalid checkpoint IDs
 140→				continue
 141→			}
 142→
 143→			info := CheckpointInfo{
 144→				CheckpointID: checkpointID,
 145→			}
 146→
 147→			// Get details from metadata file (CheckpointSummary format)
 148→			if metadataFile, fileErr := checkpointTree.File(paths.MetadataFileName); fileErr == nil {
 149→				if content, contentErr := metadataFile.Contents(); contentErr == nil {
 150→					var summary checkpoint.CheckpointSummary
 151→					if json.Unmarshal([]byte(content), &summary) == nil && len(summary.Sessions) > 0 {
 152→						info.CheckpointsCount = summary.CheckpointsCount
 153→						info.FilesTouched = summary.FilesTouched
 154→						info.SessionCount = len(summary.Sessions)
 155→
 156→						// Read session-level metadata for Agent, SessionID, CreatedAt, SessionIDs
 157→						for i, sessionPaths := range summary.Sessions {
 158→							if sessionPaths.Metadata != "" {
 159→								// SessionFilePaths now contains absolute paths with leading "/"
 160→								// Strip the leading "/" for tree.File() which expects paths without leading slash
 161→								sessionMetadataPath := strings.TrimPrefix(sessionPaths.Metadata, "/")
 162→								if sessionFile, sErr := tree.File(sessionMetadataPath); sErr == nil {
 163→									if sessionContent, scErr := sessionFile.Contents(); scErr == nil {
 164→										var sessionMetadata checkpoint.CommittedMetadata
 165→										if json.Unmarshal([]byte(sessionContent), &sessionMetadata) == nil {
 166→											info.SessionIDs = append(info.SessionIDs, sessionMetadata.SessionID)
 167→											// Use first session's metadata for Agent, SessionID, CreatedAt
 168→											if i == 0 {
 169→												info.Agent = sessionMetadata.Agent
 170→												info.SessionID = sessionMetadata.SessionID
 171→												info.CreatedAt = sessionMetadata.CreatedAt
 172→												info.IsTask = sessionMetadata.IsTask
 173→												info.ToolUseID = sessionMetadata.ToolUseID
 174→											}
 175→										}
 176→									}
 177→								}
 178→							}
 179→						}
 180→					}
 181→				}
 182→			}
 183→
 184→			checkpoints = append(checkpoints, info)
 185→		}
 186→	}
 187→
 188→	// Sort by time (most recent first)
 189→	sort.Slice(checkpoints, func(i, j int) bool {
 190→		return checkpoints[i].CreatedAt.After(checkpoints[j].CreatedAt)
 191→	})
 192→
 193→	return checkpoints, nil
 194→}
