 206→// isProtectedPath returns true if relPath is inside a directory that should
 207→// never be modified or deleted during rewind or other destructive operations.
 208→// Protected directories include git internals, entire metadata, and all
 209→// registered agent config directories.
 210→func isProtectedPath(relPath string) bool {
 211→	for _, dir := range protectedDirs() {
 212→		if relPath == dir || strings.HasPrefix(relPath, dir+string(filepath.Separator)) {
 213→			return true
 214→		}
 215→	}
 216→	return false
 217→}
