 265→// resolveAgentType picks the best agent type from the context and existing state.
 266→// Priority: existing state (if specific) > context value > default fallback.
 267→func resolveAgentType(ctxAgentType agent.AgentType, state *SessionState) agent.AgentType {
 268→	if state != nil && isSpecificAgentType(state.AgentType) {
 269→		return state.AgentType
