 277→// ensureMetadataBranch creates the orphan entire/checkpoints/v1 branch if it doesn't exist.
 278→// This branch has no parent and starts with an empty tree.
 279→func EnsureMetadataBranch(repo *git.Repository) error {
 280→	refName := plumbing.NewBranchReferenceName(paths.MetadataBranchName)
 281→
 282→	// Check if branch already exists
 283→	_, err := repo.Reference(refName, true)
 284→	if err == nil {
 285→		// Branch already exists
 286→		return nil
 287→	}
 288→
 289→	// Create empty tree (no files)
 290→	emptyTree := &object.Tree{Entries: []object.TreeEntry{}}
 291→	obj := repo.Storer.NewEncodedObject()
 292→	if err := emptyTree.Encode(obj); err != nil {
 293→		return fmt.Errorf("failed to encode empty tree: %w", err)
 294→	}
 295→	emptyTreeHash, err := repo.Storer.SetEncodedObject(obj)
 296→	if err != nil {
 297→		return fmt.Errorf("failed to store empty tree: %w", err)
 298→	}
 299→
 300→	// Create orphan commit (no parent)
 301→	now := time.Now()
 302→	authorName, authorEmail := GetGitAuthorFromRepo(repo)
 303→	sig := object.Signature{
 304→		Name:  authorName,
 305→		Email: authorEmail,
 306→		When:  now,
 307→	}
 308→
 309→	commit := &object.Commit{
 310→		TreeHash:  emptyTreeHash,
 311→		Author:    sig,
 312→		Committer: sig,
 313→		Message:   "Initialize metadata branch\n\nThis branch stores session metadata for the auto-commit strategy.\n",
 314→	}
 315→	// Note: No ParentHashes - this is an orphan commit
 316→
 317→	commitObj := repo.Storer.NewEncodedObject()
 318→	if err := commit.Encode(commitObj); err != nil {
 319→		return fmt.Errorf("failed to encode orphan commit: %w", err)
 320→	}
 321→	commitHash, err := repo.Storer.SetEncodedObject(commitObj)
 322→	if err != nil {
 323→		return fmt.Errorf("failed to store orphan commit: %w", err)
 324→	}
 325→
 326→	// Create branch reference
 327→	ref := plumbing.NewHashReference(refName, commitHash)
 328→	if err := repo.Storer.SetReference(ref); err != nil {
 329→		return fmt.Errorf("failed to create metadata branch: %w", err)
 330→	}
 331→
 332→	fmt.Fprintf(os.Stderr, "✓ Created orphan branch '%s' for session metadata\n", paths.MetadataBranchName)
 333→	return nil
 334→}
 335→
 336→// readCheckpointMetadata reads metadata.json from a checkpoint path on entire/checkpoints/v1.
 337→// With the new format, root metadata.json is a CheckpointSummary with Agents array.
 338→// This function reads the summary and extracts relevant fields into CheckpointInfo,
 339→// also reading session-level metadata for IsTask/ToolUseID fields.
 340→func ReadCheckpointMetadata(tree *object.Tree, checkpointPath string) (*CheckpointInfo, error) {
 341→	metadataPath := checkpointPath + "/metadata.json"
 342→	file, err := tree.File(metadataPath)
 343→	if err != nil {
 344→		return nil, fmt.Errorf("failed to find metadata at %s: %w", metadataPath, err)
 345→	}
 346→
 347→	content, err := file.Contents()
 348→	if err != nil {
 349→		return nil, fmt.Errorf("failed to read metadata: %w", err)
 350→	}
 351→
 352→	// Try to parse as CheckpointSummary first (new format)
 353→	var summary checkpoint.CheckpointSummary
 354→	if err := json.Unmarshal([]byte(content), &summary); err == nil {
 355→		// If we have sessions array, this is the new format
 356→		if len(summary.Sessions) > 0 {
 357→			info := &CheckpointInfo{
 358→				CheckpointID:     summary.CheckpointID,
 359→				CheckpointsCount: summary.CheckpointsCount,
 360→				FilesTouched:     summary.FilesTouched,
 361→				SessionCount:     len(summary.Sessions),
 362→			}
 363→
 364→			// Read all sessions' metadata to populate SessionIDs and get other fields from first session
 365→			var sessionIDs []string
 366→			for i, sessionPaths := range summary.Sessions {
 367→				if sessionPaths.Metadata != "" {
 368→					// SessionFilePaths now contains absolute paths with leading "/"
 369→					// Strip the leading "/" for tree.File() which expects paths without leading slash
 370→					sessionMetadataPath := strings.TrimPrefix(sessionPaths.Metadata, "/")
 371→					if sessionFile, err := tree.File(sessionMetadataPath); err == nil {
 372→						if sessionContent, err := sessionFile.Contents(); err == nil {
 373→							var sessionMetadata checkpoint.CommittedMetadata
 374→							if json.Unmarshal([]byte(sessionContent), &sessionMetadata) == nil {
 375→								sessionIDs = append(sessionIDs, sessionMetadata.SessionID)
 376→								// Use first session for Agent, SessionID, CreatedAt, IsTask, ToolUseID
 377→								if i == 0 {
 378→									info.Agent = sessionMetadata.Agent
 379→									info.SessionID = sessionMetadata.SessionID
 380→									info.CreatedAt = sessionMetadata.CreatedAt
 381→									info.IsTask = sessionMetadata.IsTask
 382→									info.ToolUseID = sessionMetadata.ToolUseID
 383→								}
 384→							}
 385→						}
 386→					}
 387→				}
 388→			}
 389→			info.SessionIDs = sessionIDs
 390→
 391→			return info, nil
 392→		}
 393→	}
 394→
 395→	// Fall back to parsing as CheckpointInfo (old format or direct info)
 396→	var metadata CheckpointInfo
 397→	if err := json.Unmarshal([]byte(content), &metadata); err != nil {
 398→		return nil, fmt.Errorf("failed to parse metadata: %w", err)
 399→	}
 400→
 401→	return &metadata, nil
 402→}
