 424→// ExtractFirstPrompt extracts and truncates the first meaningful prompt from prompt content.
 425→// Prompts are separated by "\n\n---\n\n". Skips empty prompts and separator-only content.
 426→// Returns empty string if no valid prompt is found.
 427→func ExtractFirstPrompt(content string) string {
 428→	if content == "" {
 429→		return ""
 430→	}
 431→
 432→	// Prompts are separated by "\n\n---\n\n"
 433→	// Find the first non-empty prompt
 434→	prompts := strings.Split(content, "\n\n---\n\n")
 435→	var firstPrompt string
 436→	for _, p := range prompts {
 437→		cleaned := strings.TrimSpace(p)
 438→		// Skip empty prompts or prompts that are just dashes/separators
 439→		if cleaned == "" || isOnlySeparators(cleaned) {
 440→			continue
 441→		}
 442→		firstPrompt = cleaned
 443→		break
 444→	}
 445→
 446→	if firstPrompt == "" {
 447→		return ""
 448→	}
 449→
 450→	return TruncateDescription(firstPrompt, MaxDescriptionLength)
 451→}
