 470→// ReadAgentTypeFromTree reads the agent type from a checkpoint's metadata.json file in a git tree.
 471→// If metadata.json doesn't exist (shadow branches), it falls back to detecting the agent
 472→// from the presence of agent-specific config files (.gemini/settings.json or .claude/).
 473→// Returns agent.AgentTypeUnknown if the agent type cannot be determined.
 474→func ReadAgentTypeFromTree(tree *object.Tree, checkpointPath string) agent.AgentType {
 475→	// First, try to read from metadata.json (present in condensed/committed checkpoints)
 476→	metadataPath := checkpointPath + "/" + paths.MetadataFileName
 477→	if file, err := tree.File(metadataPath); err == nil {
 478→		if content, err := file.Contents(); err == nil {
 479→			var metadata checkpoint.CommittedMetadata
 480→			if err := json.Unmarshal([]byte(content), &metadata); err == nil && metadata.Agent != "" {
 481→				return metadata.Agent
 482→			}
 483→		}
 484→	}
 485→
 486→	// Fall back to detecting agent from config files (shadow branches don't have metadata.json)
 487→	// Check for Gemini config
 488→	if _, err := tree.File(".gemini/settings.json"); err == nil {
 489→		return agent.AgentTypeGemini
 490→	}
 491→	// Check for Claude config (either settings.local.json or settings.json in .claude/)
 492→	if _, err := tree.Tree(".claude"); err == nil {
 493→		return agent.AgentTypeClaudeCode
 494→	}
 495→
 496→	return agent.AgentTypeUnknown
 497→}
