 499→// isOnlySeparators checks if a string contains only dashes, spaces, and newlines.
 500→func isOnlySeparators(s string) bool {
 501→	for _, r := range s {
 502→		if r != '-' && r != ' ' && r != '\n' && r != '\r' && r != '\t' {
 503→			return false
 504→		}
 505→	}
 506→	return true
 507→}
