 509→// ReadAllSessionPromptsFromTree reads the first prompt for all sessions in a multi-session checkpoint.
 510→// Returns a slice of prompts parallel to sessionIDs (oldest to newest).
 511→// For single-session checkpoints, returns a slice with just the root prompt.
 512→func ReadAllSessionPromptsFromTree(tree *object.Tree, checkpointPath string, sessionCount int, sessionIDs []string) []string {
 513→	if sessionCount <= 1 || len(sessionIDs) <= 1 {
 514→		// Single session - just return the root prompt
 515→		prompt := ReadSessionPromptFromTree(tree, checkpointPath)
 516→		if prompt != "" {
 517→			return []string{prompt}
 518→		}
 519→		return nil
 520→	}
 521→
 522→	// Multi-session: read prompts from archived folders (0/, 1/, etc.) and root
 523→	prompts := make([]string, len(sessionIDs))
 524→
 525→	// Read archived session prompts (folders 0, 1, ... N-2)
 526→	for i := range sessionCount - 1 {
 527→		archivedPath := fmt.Sprintf("%s/%d", checkpointPath, i)
 528→		prompts[i] = ReadSessionPromptFromTree(tree, archivedPath)
 529→	}
 530→
 531→	// Read the most recent session prompt (at root level)
 532→	prompts[len(prompts)-1] = ReadSessionPromptFromTree(tree, checkpointPath)
 533→
 534→	return prompts
 535→}
