 582→// OpenRepository opens the git repository with linked worktree support enabled.
 583→// It uses git.PlainOpenWithOptions with EnableDotGitCommonDir set to true,
 584→// which is required for proper operation in git worktrees created via 'git worktree add'.
 585→//
 586→// Without EnableDotGitCommonDir, go-git operations in worktrees can silently fail:
 587→// - Commits appear to succeed but are not persisted
 588→// - Refs are written to incorrect locations
 589→// - The worktree's HEAD/index don't get updated properly
 590→//
 591→// This happens because worktrees use .git as a file (pointing to the main repo)
 592→// rather than a directory, and go-git needs to route paths correctly between
 593→// shared (.git/) and per-worktree (.git/worktrees/<name>/) locations.
 594→//
 595→// The function first uses 'git rev-parse --show-toplevel' to find the repository
 596→// root, which works correctly even when called from a subdirectory within the repo.
 597→func OpenRepository() (*git.Repository, error) {
 598→	// First, find the repository root using git rev-parse --show-toplevel
 599→	// This works correctly from any subdirectory within the repository
 600→	repoRoot, err := GetWorktreePath()
 601→	if err != nil {
 602→		// Fallback to current directory if git command fails
 603→		// (e.g., if git is not installed or we're not in a repo)
 604→		repoRoot = "."
 605→	}
 606→
 607→	repo, err := git.PlainOpenWithOptions(repoRoot, &git.PlainOpenOptions{
 608→		EnableDotGitCommonDir: true,
 609→	})
 610→	if err != nil {
 611→		return nil, fmt.Errorf("failed to open repository: %w", err)
 612→	}
 613→	return repo, nil
 614→}
 615→
 616→// IsInsideWorktree returns true if the current directory is inside a git worktree
 617→// (as opposed to the main repository). Worktrees have .git as a file pointing
 618→// to the main repo, while the main repo has .git as a directory.
 619→// This function works correctly from any subdirectory within the repository.
 620→func IsInsideWorktree() bool {
 621→	// First find the repository root
 622→	repoRoot, err := GetWorktreePath()
 623→	if err != nil {
 624→		return false
 625→	}
 626→
 627→	gitPath := filepath.Join(repoRoot, gitDir)
 628→	gitInfo, err := os.Stat(gitPath)
 629→	if err != nil {
 630→		return false
 631→	}
 632→	return !gitInfo.IsDir()
 633→}
 634→
 635→// GetMainRepoRoot returns the root directory of the main repository.
 636→// In the main repo, this is the worktree path (repo root).
 637→// In a worktree, this parses the .git file to find the main repo.
 638→// This function works correctly from any subdirectory within the repository.
 639→//
 640→// Per gitrepository-layout(5), a worktree's .git file is a "gitfile" containing
 641→// "gitdir: <path>" pointing to $GIT_DIR/worktrees/<id> in the main repository.
 642→// See: https://git-scm.com/docs/gitrepository-layout
 643→func GetMainRepoRoot() (string, error) {
 644→	// First find the worktree/repo root
 645→	repoRoot, err := GetWorktreePath()
 646→	if err != nil {
 647→		return "", fmt.Errorf("failed to get worktree path: %w", err)
 648→	}
 649→
 650→	if !IsInsideWorktree() {
 651→		return repoRoot, nil
 652→	}
 653→
 654→	// Worktree .git file contains: "gitdir: /path/to/main/.git/worktrees/<id>"
 655→	gitFilePath := filepath.Join(repoRoot, gitDir)
 656→	content, err := os.ReadFile(gitFilePath) //nolint:gosec // G304: gitFilePath is constructed from repo root, not user input
 657→	if err != nil {
 658→		return "", fmt.Errorf("failed to read .git file: %w", err)
 659→	}
 660→
 661→	gitdir := strings.TrimSpace(string(content))
 662→	gitdir = strings.TrimPrefix(gitdir, "gitdir: ")
 663→
 664→	// Extract main repo root: everything before "/.git/"
 665→	idx := strings.LastIndex(gitdir, "/.git/")
 666→	if idx < 0 {
 667→		return "", fmt.Errorf("unexpected gitdir format: %s", gitdir)
 668→	}
 669→	return gitdir[:idx], nil
 670→}
 671→
 672→// GetGitCommonDir returns the path to the shared git directory.
 673→// In a regular checkout, this is .git/
 674→// In a worktree, this is the main repo's .git/ (not .git/worktrees/<name>/)
 675→// Uses git rev-parse --git-common-dir for reliable handling of worktrees.
 676→func GetGitCommonDir() (string, error) {
 677→	ctx := context.Background()
 678→	cmd := exec.CommandContext(ctx, "git", "rev-parse", "--git-common-dir")
 679→	cmd.Dir = "."
 680→	output, err := cmd.Output()
 681→	if err != nil {
 682→		return "", fmt.Errorf("failed to get git common dir: %w", err)
 683→	}
 684→
 685→	commonDir := strings.TrimSpace(string(output))
 686→
 687→	// git rev-parse --git-common-dir returns relative paths from the working directory,
 688→	// so we need to make it absolute if it isn't already
 689→	if !filepath.IsAbs(commonDir) {
 690→		commonDir = filepath.Join(".", commonDir)
 691→	}
 692→
 693→	return filepath.Clean(commonDir), nil
 694→}
