 696→// GetWorktreePath returns the absolute path to the current worktree root.
 697→// This is the working directory path, not the git directory.
 698→func GetWorktreePath() (string, error) {
 699→	ctx := context.Background()
 700→	cmd := exec.CommandContext(ctx, "git", "rev-parse", "--show-toplevel")
 701→	output, err := cmd.Output()
 702→	if err != nil {
 703→		return "", fmt.Errorf("failed to get worktree path: %w", err)
 704→	}
 705→	return strings.TrimSpace(string(output)), nil
 706→}
