 708→// EnsureEntireGitignore ensures all required entries are in .entire/.gitignore
 709→// Works correctly from any subdirectory within the repository.
 710→func EnsureEntireGitignore() error {
 711→	// Get absolute path for the gitignore file
 712→	gitignoreAbs, err := paths.AbsPath(entireGitignore)
 713→	if err != nil {
 714→		gitignoreAbs = entireGitignore // Fallback to relative
 715→	}
 716→
 717→	// Read existing content
 718→	var content string
 719→	if data, err := os.ReadFile(gitignoreAbs); err == nil { //nolint:gosec // path is from AbsPath or constant
 720→		content = string(data)
 721→	}
 722→
 723→	// All entries that should be in .entire/.gitignore
 724→	requiredEntries := []string{
 725→		"tmp/",
 726→		"settings.local.json",
 727→		"metadata/",
 728→		"logs/",
 729→	}
 730→
 731→	// Track what needs to be added
 732→	var toAdd []string
 733→	for _, entry := range requiredEntries {
 734→		if !strings.Contains(content, entry) {
 735→			toAdd = append(toAdd, entry)
 736→		}
 737→	}
 738→
 739→	// Nothing to add
 740→	if len(toAdd) == 0 {
 741→		return nil
 742→	}
 743→
 744→	// Ensure .entire directory exists
 745→	if err := os.MkdirAll(filepath.Dir(gitignoreAbs), 0o750); err != nil {
 746→		return fmt.Errorf("failed to create .entire directory: %w", err)
 747→	}
 748→
 749→	// Append missing entries to gitignore
 750→	var sb strings.Builder
 751→	for _, entry := range toAdd {
 752→		sb.WriteString(entry + "\n")
 753→	}
 754→	content += sb.String()
 755→
 756→	if err := os.WriteFile(gitignoreAbs, []byte(content), 0o644); err != nil { //nolint:gosec // path is from AbsPath or constant
 757→		return fmt.Errorf("failed to write gitignore: %w", err)
 758→	}
 759→	return nil
 760→}
 761→
 762→// checkCanRewind checks if working directory is clean enough for rewind.
 763→// Returns (canRewind, reason, error). Shared by shadow and linear-shadow strategies.
 764→func checkCanRewind() (bool, string, error) {
 765→	repo, err := OpenRepository()
 766→	if err != nil {
 767→		return false, "", fmt.Errorf("failed to open git repository: %w", err)
 768→	}
 769→
 770→	worktree, err := repo.Worktree()
 771→	if err != nil {
 772→		return false, "", fmt.Errorf("failed to get worktree: %w", err)
 773→	}
 774→
 775→	status, err := worktree.Status()
 776→	if err != nil {
 777→		return false, "", fmt.Errorf("failed to get status: %w", err)
 778→	}
 779→
 780→	if status.IsClean() {
 781→		return true, "", nil
 782→	}
 783→
 784→	var modified, added, deleted []string
 785→	for file, st := range status {
 786→		// Skip .entire directory
 787→		if paths.IsInfrastructurePath(file) {
 788→			continue
 789→		}
 790→
 791→		// Skip untracked files
 792→		if st.Worktree == git.Untracked {
 793→			continue
 794→		}
 795→
 796→		switch {
 797→		case st.Staging == git.Added || st.Worktree == git.Added:
 798→			added = append(added, file)
 799→		case st.Staging == git.Deleted || st.Worktree == git.Deleted:
 800→			deleted = append(deleted, file)
 801→		case st.Staging == git.Modified || st.Worktree == git.Modified:
 802→			modified = append(modified, file)
 803→		}
 804→	}
 805→
 806→	if len(modified) == 0 && len(added) == 0 && len(deleted) == 0 {
 807→		return true, "", nil
 808→	}
 809→
 810→	var msg strings.Builder
 811→	msg.WriteString("You have uncommitted changes:\n")
 812→	for _, f := range modified {
 813→		msg.WriteString(fmt.Sprintf("  modified:   %s\n", f))
 814→	}
 815→	for _, f := range added {
 816→		msg.WriteString(fmt.Sprintf("  added:      %s\n", f))
 817→	}
 818→	for _, f := range deleted {
 819→		msg.WriteString(fmt.Sprintf("  deleted:    %s\n", f))
 820→	}
 821→	msg.WriteString("\nPlease commit or stash your changes before rewinding.")
 822→
 823→	return false, msg.String(), nil
 824→}
 825→
 826→// checkCanRewindWithWarning checks working directory and returns a warning with diff stats.
 827→// Unlike checkCanRewind, this always returns canRewind=true but includes a warning message
 828→// with +/- line stats for uncommitted changes. Used by manual-commit strategy.
 829→func checkCanRewindWithWarning() (bool, string, error) {
 830→	repo, err := OpenRepository()
 831→	if err != nil {
 832→		// Can't open repo - still allow rewind but without stats
 833→		return true, "", nil //nolint:nilerr // Rewind allowed even if repo can't be opened
 834→	}
 835→
 836→	worktree, err := repo.Worktree()
 837→	if err != nil {
 838→		return true, "", nil //nolint:nilerr // Rewind allowed even if worktree can't be accessed
 839→	}
 840→
 841→	status, err := worktree.Status()
 842→	if err != nil {
 843→		return true, "", nil //nolint:nilerr // Rewind allowed even if status can't be retrieved
 844→	}
 845→
 846→	if status.IsClean() {
 847→		return true, "", nil
 848→	}
 849→
 850→	// Get HEAD commit tree for comparison - if we can't get it, just return without stats
 851→	head, err := repo.Head()
 852→	if err != nil {
 853→		return true, "", nil //nolint:nilerr // Rewind allowed even without HEAD (e.g., empty repo)
 854→	}
 855→
 856→	headCommit, err := repo.CommitObject(head.Hash())
 857→	if err != nil {
 858→		return true, "", nil //nolint:nilerr // Rewind allowed even if commit lookup fails
 859→	}
 860→
 861→	headTree, err := headCommit.Tree()
 862→	if err != nil {
 863→		return true, "", nil //nolint:nilerr // Rewind allowed even if tree lookup fails
 864→	}
 865→
 866→	type fileChange struct {
 867→		status   string // "modified", "added", "deleted"
 868→		added    int
 869→		removed  int
 870→		filename string
 871→	}
 872→
 873→	var changes []fileChange
 874→	// Use repo root, not cwd - git status returns paths relative to repo root
 875→	repoRoot, err := GetWorktreePath()
 876→	if err != nil {
 877→		return true, "", nil //nolint:nilerr // Rewind allowed even if repo root lookup fails
 878→	}
 879→
 880→	for file, st := range status {
 881→		// Skip .entire directory
 882→		if paths.IsInfrastructurePath(file) {
 883→			continue
 884→		}
 885→
 886→		// Skip untracked files
 887→		if st.Worktree == git.Untracked {
 888→			continue
 889→		}
 890→
 891→		var change fileChange
 892→		change.filename = file
 893→
 894→		switch {
 895→		case st.Staging == git.Added || st.Worktree == git.Added:
 896→			change.status = "added"
 897→			// New file - count all lines as added
 898→			absPath := filepath.Join(repoRoot, file)
 899→			if content, err := os.ReadFile(absPath); err == nil { //nolint:gosec // absPath is repo root + relative path from git status
 900→				change.added = countLines(content)
 901→			}
 902→		case st.Staging == git.Deleted || st.Worktree == git.Deleted:
 903→			change.status = "deleted"
 904→			// Deleted file - count lines from HEAD as removed
 905→			if entry, err := headTree.File(file); err == nil {
 906→				if content, err := entry.Contents(); err == nil {
 907→					change.removed = countLines([]byte(content))
 908→				}
 909→			}
 910→		case st.Staging == git.Modified || st.Worktree == git.Modified:
 911→			change.status = "modified"
 912→			// Modified file - compute diff stats
 913→			var headContent, workContent []byte
 914→			if entry, err := headTree.File(file); err == nil {
 915→				if content, err := entry.Contents(); err == nil {
 916→					headContent = []byte(content)
 917→				}
 918→			}
 919→			absPath := filepath.Join(repoRoot, file)
 920→			if content, err := os.ReadFile(absPath); err == nil { //nolint:gosec // absPath is repo root + relative path from git status
 921→				workContent = content
 922→			}
 923→			if headContent != nil && workContent != nil {
 924→				change.added, change.removed = computeDiffStats(headContent, workContent)
 925→			}
 926→		default:
 927→			continue
 928→		}
 929→
 930→		changes = append(changes, change)
 931→	}
 932→
 933→	if len(changes) == 0 {
 934→		return true, "", nil
 935→	}
 936→
 937→	// Sort changes by filename for consistent output
 938→	sort.Slice(changes, func(i, j int) bool {
 939→		return changes[i].filename < changes[j].filename
 940→	})
 941→
 942→	var msg strings.Builder
 943→	msg.WriteString("The following uncommitted changes will be reverted:\n")
 944→
 945→	totalAdded, totalRemoved := 0, 0
 946→	for _, c := range changes {
 947→		totalAdded += c.added
 948→		totalRemoved += c.removed
 949→
 950→		var stats string
 951→		switch {
 952→		case c.added > 0 && c.removed > 0:
 953→			stats = fmt.Sprintf("+%d/-%d", c.added, c.removed)
 954→		case c.added > 0:
 955→			stats = fmt.Sprintf("+%d", c.added)
 956→		case c.removed > 0:
 957→			stats = fmt.Sprintf("-%d", c.removed)
 958→		}
 959→
 960→		msg.WriteString(fmt.Sprintf("  %-10s %s", c.status+":", c.filename))
 961→		if stats != "" {
 962→			msg.WriteString(fmt.Sprintf(" (%s)", stats))
 963→		}
 964→		msg.WriteString("\n")
 965→	}
 966→
 967→	if totalAdded > 0 || totalRemoved > 0 {
 968→		msg.WriteString(fmt.Sprintf("\nTotal: +%d/-%d lines\n", totalAdded, totalRemoved))
 969→	}
 970→
 971→	return true, msg.String(), nil
 972→}
