 974→// countLines counts the number of lines in content.
 975→func countLines(content []byte) int {
 976→	if len(content) == 0 {
 977→		return 0
 978→	}
 979→	count := 1
 980→	for _, b := range content {
 981→		if b == '\n' {
 982→			count++
 983→		}
 984→	}
 985→	// Don't count trailing newline as extra line
 986→	if len(content) > 0 && content[len(content)-1] == '\n' {
 987→		count--
 988→	}
 989→	return count
 990→}
