 992→// computeDiffStats computes added and removed line counts between old and new content.
 993→// Uses a simple line-based diff algorithm.
 994→func computeDiffStats(oldContent, newContent []byte) (added, removed int) {
 995→	oldLines := splitLines(oldContent)
 996→	newLines := splitLines(newContent)
 997→
 998→	// Build a set of old lines with counts
 999→	oldSet := make(map[string]int)
1000→	for _, line := range oldLines {
1001→		oldSet[line]++
1002→	}
1003→
1004→	// Check which new lines are truly new
1005→	for _, line := range newLines {
1006→		if oldSet[line] > 0 {
1007→			oldSet[line]--
1008→		} else {
1009→			added++
1010→		}
1011→	}
1012→
1013→	// Remaining old lines are removed
1014→	for _, count := range oldSet {
1015→		removed += count
1016→	}
1017→
1018→	return added, removed
1019→}
