1021→// splitLines splits content into lines, preserving empty lines.
1022→func splitLines(content []byte) []string {
1023→	if len(content) == 0 {
1024→		return nil
1025→	}
1026→	s := string(content)
1027→	// Remove trailing newline to avoid empty last element
1028→	s = strings.TrimSuffix(s, "\n")
1029→	return strings.Split(s, "\n")
1030→}
