1048→// StageFiles stages modified, new, and deleted files to the git worktree.
1049→//
1050→// This function handles three categories of file changes:
1051→//  1. Modified files: existing files that have been changed
1052→//  2. New files: files that were created during the session
1053→//  3. Deleted files: files that were removed during the session
1054→//
1055→// Error Handling Strategy:
1056→//   - Individual file staging errors are logged to stderr but don't fail the operation
1057→//   - This ensures that partial staging succeeds even if some files have issues
1058→//   - If a modified file no longer exists, it's treated as a deletion
1059→//
1060→// The stageCtx parameter is used for user-facing messages to indicate whether
1061→// this is staging for a session checkpoint or a task checkpoint.
1062→func StageFiles(worktree *git.Worktree, modified, newFiles, deleted []string, stageCtx StageFilesContext) {
1063→	// Get repo root for resolving file paths
1064→	// This is critical because fileExists() uses os.Stat() which resolves relative to CWD,
1065→	// but worktree.Add/Remove resolve relative to repo root. If CWD != repo root,
1066→	// fileExists() could return false for existing files, causing worktree.Remove()
1067→	// to incorrectly delete them.
1068→	repoRoot := worktree.Filesystem.Root()
1069→
1070→	// Stage modified files
1071→	for _, file := range modified {
1072→		// Resolve path relative to repo root for existence check
1073→		absPath := filepath.Join(repoRoot, file)
1074→		if fileExists(absPath) {
1075→			if _, err := worktree.Add(file); err != nil {
1076→				fmt.Fprintf(os.Stderr, "  Failed to stage %s: %v\n", file, err)
1077→			} else {
1078→				fmt.Fprintf(os.Stderr, "  Staged: %s\n", file)
1079→			}
1080→		} else {
1081→			// File was deleted - stage the deletion
1082→			if _, err := worktree.Remove(file); err != nil {
1083→				fmt.Fprintf(os.Stderr, "  File not found or deleted: %s\n", file)
1084→			}
1085→		}
1086→	}
1087→
1088→	// Stage new files
1089→	if len(newFiles) > 0 {
1090→		fmt.Fprintf(os.Stderr, "Staging %d new files created during %s:\n", len(newFiles), stageCtx)
1091→		for _, file := range newFiles {
1092→			if _, err := worktree.Add(file); err != nil {
1093→				fmt.Fprintf(os.Stderr, "  Failed to stage %s: %v\n", file, err)
1094→			} else {
1095→				fmt.Fprintf(os.Stderr, "  Staged new file: %s\n", file)
1096→			}
1097→		}
1098→	}
1099→
1100→	// Stage deleted files
1101→	for _, file := range deleted {
1102→		if _, err := worktree.Remove(file); err != nil {
1103→			fmt.Fprintf(os.Stderr, "  Failed to stage deleted file %s: %v\n", file, err)
1104→		} else {
1105→			fmt.Fprintf(os.Stderr, "  Staged deleted file: %s\n", file)
1106→		}
1107→	}
1108→}
