1199→// ErrBranchNotFound is returned by DeleteBranchCLI when the branch does not exist.
1200→var ErrBranchNotFound = errors.New("branch not found")
1201→
1202→// DeleteBranchCLI deletes a git branch using the git CLI.
1203→// Uses `git branch -D` instead of go-git's RemoveReference because go-git v5
1204→// doesn't properly persist deletions when refs are packed (.git/packed-refs)
1205→// or in a worktree context. This is the same class of go-git v5 bug that
1206→// affects checkout and reset --hard (see HardResetWithProtection).
1207→//
1208→// Returns ErrBranchNotFound if the branch does not exist, allowing callers
1209→// to use errors.Is for idempotent deletion patterns.
1210→func DeleteBranchCLI(branchName string) error {
1211→	ctx := context.Background()
1212→
1213→	// Pre-check: verify the branch exists so callers get a structured error
1214→	// instead of parsing git's output string (which varies across locales).
1215→	// git show-ref exits 1 for "not found" and 128+ for fatal errors (corrupt
1216→	// repo, permissions, not a git directory). Only map exit code 1 to
1217→	// ErrBranchNotFound; propagate other failures as-is.
1218→	check := exec.CommandContext(ctx, "git", "show-ref", "--verify", "--quiet", "refs/heads/"+branchName) //nolint:gosec // branchName comes from internal shadow branch naming
1219→	if err := check.Run(); err != nil {
1220→		var exitErr *exec.ExitError
1221→		if errors.As(err, &exitErr) && exitErr.ExitCode() == 1 {
1222→			return fmt.Errorf("%w: %s", ErrBranchNotFound, branchName)
1223→		}
1224→		return fmt.Errorf("failed to check branch %s: %w", branchName, err)
1225→	}
1226→
1227→	cmd := exec.CommandContext(ctx, "git", "branch", "-D", "--", branchName)
1228→	if output, err := cmd.CombinedOutput(); err != nil {
1229→		return fmt.Errorf("failed to delete branch %s: %s: %w", branchName, strings.TrimSpace(string(output)), err)
1230→	}
1231→	return nil
1232→}
