1245→// HardResetWithProtection performs a git reset --hard to the specified commit.
1246→// Uses the git CLI instead of go-git because go-git's HardReset incorrectly
1247→// deletes untracked directories (like .entire/) even when they're in .gitignore.
1248→// Returns the short commit ID (7 chars) on success for display purposes.
1249→func HardResetWithProtection(commitHash plumbing.Hash) (shortID string, err error) {
1250→	ctx := context.Background()
1251→	hashStr := commitHash.String()
1252→	cmd := exec.CommandContext(ctx, "git", "reset", "--hard", hashStr) //nolint:gosec // hashStr is a plumbing.Hash, not user input
1253→	if output, err := cmd.CombinedOutput(); err != nil {
1254→		return "", fmt.Errorf("reset failed: %s: %w", strings.TrimSpace(string(output)), err)
1255→	}
1256→
1257→	// Return short commit ID for display
1258→	shortID = hashStr
1259→	if len(shortID) > 7 {
1260→		shortID = shortID[:7]
1261→	}
1262→	return shortID, nil
1263→}
