1265→// collectUntrackedFiles collects all untracked files in the working directory.
1266→// This is used to capture the initial state when starting a session,
1267→// ensuring untracked files present at session start are preserved during rewind.
1268→// Excludes protected directories (.git/, .entire/, and agent config directories).
1269→// Works correctly from any subdirectory within the repository.
1270→func collectUntrackedFiles() ([]string, error) {
1271→	// Get repository root to walk from there
1272→	repoRoot, err := GetWorktreePath()
1273→	if err != nil {
1274→		repoRoot = "." // Fallback to current directory
1275→	}
1276→
1277→	var untrackedFiles []string
1278→	err = filepath.Walk(repoRoot, func(path string, info os.FileInfo, walkErr error) error {
1279→		if walkErr != nil {
1280→			return nil //nolint:nilerr // Skip filesystem errors during walk
1281→		}
1282→
1283→		// Get path relative to repo root
1284→		relPath, err := filepath.Rel(repoRoot, path)
1285→		if err != nil {
1286→			return nil //nolint:nilerr // Skip paths we can't make relative
1287→		}
1288→
1289→		// Skip directories
1290→		if info.IsDir() {
1291→			if isProtectedPath(relPath) {
1292→				return filepath.SkipDir
1293→			}
1294→			return nil
1295→		}
1296→
1297→		// Skip files in protected directories (shouldn't reach here due to SkipDir, but safety check)
1298→		if isProtectedPath(relPath) {
1299→			return nil
1300→		}
1301→
1302→		untrackedFiles = append(untrackedFiles, relPath)
1303→		return nil
1304→	})
1305→	if err != nil {
1306→		return nil, fmt.Errorf("failed to walk directory: %w", err)
1307→	}
1308→
1309→	return untrackedFiles, nil
1310→}
