1339→// createCommit creates a commit object
1340→func createCommit(repo *git.Repository, treeHash, parentHash plumbing.Hash, message, authorName, authorEmail string) (plumbing.Hash, error) { //nolint:unparam // already present in codebase
1341→	now := time.Now()
1342→	sig := object.Signature{
1343→		Name:  authorName,
