1373→// getSessionDescriptionFromTree reads the first line of prompt.txt or context.md from a git tree.
1374→// This is the tree-based equivalent of getSessionDescription (which reads from filesystem).
1375→//
1376→// If metadataDir is provided, looks for files at metadataDir/prompt.txt or metadataDir/context.md.
1377→// If metadataDir is empty, first tries the root of the tree (for when the tree is already
1378→// the session directory, e.g., auto-commit strategy's sharded metadata), then falls back to
1379→// searching for .entire/metadata/*/prompt.txt or context.md (for full worktree trees).
1380→func getSessionDescriptionFromTree(tree *object.Tree, metadataDir string) string {
1381→	// Helper to read first line from a file in tree
1382→	readFirstLine := func(path string) string {
1383→		file, err := tree.File(path)
1384→		if err != nil {
1385→			return ""
1386→		}
1387→		content, err := file.Contents()
1388→		if err != nil {
1389→			return ""
1390→		}
1391→		lines := strings.SplitN(content, "\n", 2)
1392→		if len(lines) > 0 && lines[0] != "" {
1393→			desc := strings.TrimSpace(lines[0])
1394→			// Remove markdown header prefix if present
1395→			return strings.TrimPrefix(desc, "# ")
1396→		}
1397→		return ""
1398→	}
1399→
1400→	// If metadataDir is provided, look there directly
1401→	if metadataDir != "" {
1402→		if desc := readFirstLine(metadataDir + "/" + paths.PromptFileName); desc != "" {
1403→			return desc
1404→		}
1405→		if desc := readFirstLine(metadataDir + "/" + paths.ContextFileName); desc != "" {
1406→			return desc
1407→		}
1408→		return NoDescription
1409→	}
1410→
1411→	// No metadataDir provided - first try looking at the root of the tree
1412→	// (used when the tree is already the session directory)
1413→	if desc := readFirstLine(paths.PromptFileName); desc != "" {
1414→		return desc
1415→	}
1416→	if desc := readFirstLine(paths.ContextFileName); desc != "" {
1417→		return desc
1418→	}
1419→
1420→	// Fall back to searching for .entire/metadata/*/prompt.txt or context.md
1421→	// (used when the tree is the full worktree)
1422→	var desc string
1423→	//nolint:errcheck // We ignore errors here as we're just searching for a description
1424→	_ = tree.Files().ForEach(func(f *object.File) error {
1425→		if desc != "" {
1426→			return nil // Already found description
1427→		}
1428→		name := f.Name
1429→		if strings.Contains(name, ".entire/metadata/") {
1430→			if strings.HasSuffix(name, "/"+paths.PromptFileName) || strings.HasSuffix(name, "/"+paths.ContextFileName) {
1431→				content, err := f.Contents()
1432→				if err != nil {
1433→					return nil //nolint:nilerr // Skip files we can't read, continue searching
1434→				}
1435→				lines := strings.SplitN(content, "\n", 2)
1436→				if len(lines) > 0 && lines[0] != "" {
1437→					desc = strings.TrimSpace(lines[0])
1438→					desc = strings.TrimPrefix(desc, "# ")
1439→				}
1440→			}
1441→		}
1442→		return nil
1443→	})
1444→
1445→	if desc != "" {
1446→		return desc
1447→	}
1448→	return NoDescription
1449→}
