1489→// GetDefaultBranchName returns the name of the default branch.
1490→// First checks origin/HEAD, then falls back to checking if main/master exists.
1491→// Returns empty string if unable to determine.
1492→// NOTE: Duplicated from cli/git_operations.go - see ENT-129 for consolidation.
1493→func GetDefaultBranchName(repo *git.Repository) string {
1494→	// Try to get the symbolic reference for origin/HEAD
1495→	// Use resolved=false to get the symbolic ref itself, then extract its target
1496→	ref, err := repo.Reference(plumbing.NewRemoteReferenceName("origin", "HEAD"), false)
1497→	if err == nil && ref != nil && ref.Type() == plumbing.SymbolicReference {
1498→		target := ref.Target().String()
1499→		if branchName, found := strings.CutPrefix(target, "refs/remotes/origin/"); found {
1500→			return branchName
1501→		}
1502→	}
1503→
1504→	// Fallback: check if origin/main or origin/master exists
1505→	if _, err := repo.Reference(plumbing.NewRemoteReferenceName("origin", branchMain), true); err == nil {
1506→		return branchMain
1507→	}
1508→	if _, err := repo.Reference(plumbing.NewRemoteReferenceName("origin", branchMaster), true); err == nil {
1509→		return branchMaster
1510→	}
1511→
1512→	// Final fallback: check local branches
1513→	if _, err := repo.Reference(plumbing.NewBranchReferenceName(branchMain), true); err == nil {
1514→		return branchMain
1515→	}
1516→	if _, err := repo.Reference(plumbing.NewBranchReferenceName(branchMaster), true); err == nil {
1517→		return branchMaster
1518→	}
1519→
1520→	return ""
1521→}
1522→
1523→// IsOnDefaultBranch checks if the repository HEAD is on the default branch.
1524→// Returns (isOnDefault, currentBranchName).
1525→// NOTE: Duplicated from cli/git_operations.go - see ENT-129 for consolidation.
1526→func IsOnDefaultBranch(repo *git.Repository) (bool, string) {
1527→	currentBranch := GetCurrentBranchName(repo)
1528→	if currentBranch == "" {
1529→		return false, ""
1530→	}
1531→
1532→	defaultBranch := GetDefaultBranchName(repo)
1533→	if defaultBranch == "" {
1534→		// Can't determine default, check common names
1535→		if currentBranch == branchMain || currentBranch == branchMaster {
1536→			return true, currentBranch
1537→		}
1538→		return false, currentBranch
1539→	}
1540→
1541→	return currentBranch == defaultBranch, currentBranch
1542→}
