 15→// Phase represents the lifecycle stage of a session.
 16→type Phase string
 17→
 18→const (
 19→	PhaseActive Phase = "active"
 20→	PhaseIdle   Phase = "idle"
 21→	PhaseEnded  Phase = "ended"
 22→)
 23→
 24→// allPhases is the canonical list of phases for enumeration (e.g., diagram generation).
 25→var allPhases = []Phase{PhaseIdle, PhaseActive, PhaseEnded}
 26→
 27→// PhaseFromString normalizes a phase string, treating empty or unknown values
 28→// as PhaseIdle for backward compatibility with pre-state-machine session files.
 29→func PhaseFromString(s string) Phase {
 30→	switch Phase(s) {
 31→	case PhaseActive, "active_committed":
 32→		// "active_committed" was removed with the 1:1 checkpoint model.
 33→		// It previously meant "agent active + commit happened during turn".
 34→		// Normalize to ACTIVE so HandleTurnEnd can finalize any pending checkpoints.
 35→		return PhaseActive
 36→	case PhaseIdle:
 37→		return PhaseIdle
 38→	case PhaseEnded:
 39→		return PhaseEnded
 40→	default:
 41→		// Backward compat: truly unknown phases normalize to idle.
 42→		return PhaseIdle
 43→	}
 44→}
 45→
 46→// IsActive reports whether the phase represents an active agent turn.
 47→func (p Phase) IsActive() bool {
 48→	return p == PhaseActive
 49→}
 50→
 51→// Event represents something that happened to a session.
 52→type Event int
 53→
 54→const (
 55→	EventTurnStart    Event = iota // Agent begins working on a prompt
 56→	EventTurnEnd                   // Agent finishes its turn
 57→	EventGitCommit                 // A git commit was made (PostCommit hook)
 58→	EventSessionStart              // Session process started (SessionStart hook)
 59→	EventSessionStop               // Session process ended (SessionStop hook)
 60→	EventCompaction                // Agent compacted context mid-turn (PreCompress hook)
 61→)
 62→
 63→// allEvents is the canonical list of events for enumeration.
 64→var allEvents = []Event{EventTurnStart, EventTurnEnd, EventGitCommit, EventSessionStart, EventSessionStop, EventCompaction}
 65→
 66→// String returns a human-readable name for the event.
 67→func (e Event) String() string {
 68→	switch e {
 69→	case EventTurnStart:
 70→		return "TurnStart"
 71→	case EventTurnEnd:
 72→		return "TurnEnd"
 73→	case EventGitCommit:
 74→		return "GitCommit"
 75→	case EventSessionStart:
 76→		return "SessionStart"
 77→	case EventSessionStop:
 78→		return "SessionStop"
 79→	case EventCompaction:
 80→		return "Compaction"
 81→	default:
 82→		return fmt.Sprintf("Event(%d)", int(e))
 83→	}
 84→}
 85→
 86→// Action represents a side effect that should be performed after a transition.
 87→// The caller is responsible for executing these -- the state machine only declares them.
 88→type Action int
 89→
 90→const (
 91→	ActionCondense               Action = iota // Condense session data to permanent storage
 92→	ActionCondenseIfFilesTouched               // Condense only if FilesTouched is non-empty
 93→	ActionDiscardIfNoFiles                     // Discard session if FilesTouched is empty
 94→	ActionWarnStaleSession                     // Warn user about stale session(s)
 95→	ActionClearEndedAt                         // Clear EndedAt timestamp (session re-entering)
 96→	ActionUpdateLastInteraction                // Update LastInteractionTime
 97→)
 98→
 99→// String returns a human-readable name for the action.
100→func (a Action) String() string {
101→	switch a {
102→	case ActionCondense:
103→		return "Condense"
104→	case ActionCondenseIfFilesTouched:
105→		return "CondenseIfFilesTouched"
106→	case ActionDiscardIfNoFiles:
107→		return "DiscardIfNoFiles"
108→	case ActionWarnStaleSession:
109→		return "WarnStaleSession"
110→	case ActionClearEndedAt:
111→		return "ClearEndedAt"
112→	case ActionUpdateLastInteraction:
113→		return "UpdateLastInteraction"
114→	default:
115→		return fmt.Sprintf("Action(%d)", int(a))
116→	}
117→}
118→
119→// TransitionContext provides read-only context for transitions that need
120→// to inspect session state without mutating it.
121→type TransitionContext struct {
122→	HasFilesTouched    bool // len(FilesTouched) > 0
123→	IsRebaseInProgress bool // .git/rebase-merge/ or .git/rebase-apply/ exists
124→}
125→
126→// TransitionResult holds the outcome of a state machine transition.
127→type TransitionResult struct {
128→	NewPhase Phase
129→	Actions  []Action
130→}
131→
132→// Transition computes the next phase and required actions given the current
133→// phase and an event. This is a pure function with no side effects.
134→//
135→// Empty or unknown phase values are normalized to PhaseIdle for backward
136→// compatibility with session state files created before phase tracking.
137→func Transition(current Phase, event Event, ctx TransitionContext) TransitionResult {
138→	// Normalize empty/unknown phase to idle for backward compatibility.
139→	current = PhaseFromString(string(current))
140→
141→	switch current {
142→	case PhaseIdle:
143→		return transitionFromIdle(event, ctx)
144→	case PhaseActive:
145→		return transitionFromActive(event, ctx)
146→	case PhaseEnded:
147→		return transitionFromEnded(event, ctx)
148→	default:
149→		// PhaseFromString guarantees we only get known phases, but the
150→		// exhaustive linter requires handling the default case.
151→		return TransitionResult{NewPhase: PhaseIdle}
152→	}
153→}
154→
155→func transitionFromIdle(event Event, ctx TransitionContext) TransitionResult {
156→	switch event {
157→	case EventTurnStart:
158→		return TransitionResult{
159→			NewPhase: PhaseActive,
160→			Actions:  []Action{ActionUpdateLastInteraction},
161→		}
162→	case EventTurnEnd:
163→		// Turn end while idle is a no-op (no active turn to end).
164→		return TransitionResult{NewPhase: PhaseIdle}
165→	case EventGitCommit:
166→		if ctx.IsRebaseInProgress {
167→			return TransitionResult{NewPhase: PhaseIdle}
168→		}
169→		return TransitionResult{
170→			NewPhase: PhaseIdle,
171→			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
172→		}
173→	case EventSessionStart:
174→		// Already condensable, no-op.
175→		return TransitionResult{NewPhase: PhaseIdle}
176→	case EventSessionStop:
177→		return TransitionResult{
178→			NewPhase: PhaseEnded,
179→			Actions:  []Action{ActionUpdateLastInteraction},
180→		}
181→	case EventCompaction:
182→		// Compaction while idle shouldn't happen, but condense if there's work.
183→		return TransitionResult{
184→			NewPhase: PhaseIdle,
185→			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
186→		}
187→	default:
188→		return TransitionResult{NewPhase: PhaseIdle}
189→	}
190→}
191→
192→func transitionFromActive(event Event, ctx TransitionContext) TransitionResult {
193→	switch event {
194→	case EventTurnStart:
195→		// Ctrl-C recovery: agent crashed or user interrupted mid-turn.
196→		return TransitionResult{
197→			NewPhase: PhaseActive,
198→			Actions:  []Action{ActionUpdateLastInteraction},
199→		}
200→	case EventTurnEnd:
201→		return TransitionResult{
202→			NewPhase: PhaseIdle,
203→			Actions:  []Action{ActionUpdateLastInteraction},
204→		}
205→	case EventGitCommit:
206→		if ctx.IsRebaseInProgress {
207→			return TransitionResult{NewPhase: PhaseActive}
208→		}
209→		return TransitionResult{
210→			NewPhase: PhaseActive,
211→			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
212→		}
213→	case EventSessionStart:
214→		return TransitionResult{
215→			NewPhase: PhaseActive,
216→			Actions:  []Action{ActionWarnStaleSession},
217→		}
218→	case EventSessionStop:
219→		return TransitionResult{
220→			NewPhase: PhaseEnded,
221→			Actions:  []Action{ActionUpdateLastInteraction},
222→		}
223→	case EventCompaction:
224→		// Compaction mid-turn: save current progress but stay active.
225→		// The transcript offset will be reset by the compaction handler.
226→		return TransitionResult{
227→			NewPhase: PhaseActive,
228→			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
229→		}
230→	default:
231→		return TransitionResult{NewPhase: PhaseActive}
232→	}
233→}
234→
235→func transitionFromEnded(event Event, ctx TransitionContext) TransitionResult {
236→	switch event {
237→	case EventTurnStart:
238→		return TransitionResult{
239→			NewPhase: PhaseActive,
240→			Actions:  []Action{ActionClearEndedAt, ActionUpdateLastInteraction},
241→		}
242→	case EventTurnEnd:
243→		// Turn end while ended is a no-op.
244→		return TransitionResult{NewPhase: PhaseEnded}
245→	case EventGitCommit:
246→		if ctx.IsRebaseInProgress {
247→			return TransitionResult{NewPhase: PhaseEnded}
248→		}
249→		if ctx.HasFilesTouched {
250→			return TransitionResult{
251→				NewPhase: PhaseEnded,
252→				Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
253→			}
254→		}
255→		return TransitionResult{
256→			NewPhase: PhaseEnded,
257→			Actions:  []Action{ActionDiscardIfNoFiles, ActionUpdateLastInteraction},
258→		}
259→	case EventSessionStart:
260→		return TransitionResult{
261→			NewPhase: PhaseIdle,
262→			Actions:  []Action{ActionClearEndedAt},
263→		}
264→	case EventSessionStop:
265→		// Already ended, no-op.
266→		return TransitionResult{NewPhase: PhaseEnded}
267→	case EventCompaction:
268→		// Compaction while ended shouldn't happen, no-op.
269→		return TransitionResult{NewPhase: PhaseEnded}
270→	default:
271→		return TransitionResult{NewPhase: PhaseEnded}
272→	}
273→}
274→
275→// ActionHandler defines strategy-specific side effects for state transitions.
276→// The compiler enforces that every strategy-specific action has a handler.
277→type ActionHandler interface {
278→	HandleCondense(state *State) error
279→	HandleCondenseIfFilesTouched(state *State) error
280→	HandleDiscardIfNoFiles(state *State) error
281→	HandleWarnStaleSession(state *State) error
282→}
283→
284→// NoOpActionHandler is a default ActionHandler where all methods are no-ops.
285→// Embed this in handler structs to only override the methods you need.
286→type NoOpActionHandler struct{}
287→
288→func (NoOpActionHandler) HandleCondense(_ *State) error               { return nil }
289→func (NoOpActionHandler) HandleCondenseIfFilesTouched(_ *State) error { return nil }
290→func (NoOpActionHandler) HandleDiscardIfNoFiles(_ *State) error       { return nil }
291→func (NoOpActionHandler) HandleWarnStaleSession(_ *State) error       { return nil }
292→
293→// ApplyTransition applies a TransitionResult to state: sets the new phase
294→// unconditionally, then executes all actions. Common actions
295→// (UpdateLastInteraction, ClearEndedAt) always run regardless of handler
296→// errors so that bookkeeping fields stay consistent with the new phase.
297→// Strategy-specific handler actions stop on the first error; subsequent
298→// handler actions are skipped but common actions continue. Returns the
299→// first handler error, or nil.
300→func ApplyTransition(state *State, result TransitionResult, handler ActionHandler) error {
301→	logCtx := logging.WithComponent(context.Background(), "session")
302→
303→	actionStrs := make([]string, len(result.Actions))
304→	for i, a := range result.Actions {
305→		actionStrs[i] = a.String()
306→	}
307→	logging.Debug(logCtx, "ApplyTransition",
308→		slog.String("session_id", state.SessionID),
309→		slog.String("old_phase", string(state.Phase)),
310→		slog.String("new_phase", string(result.NewPhase)),
311→		slog.String("actions", strings.Join(actionStrs, ",")),
312→	)
313→
314→	state.Phase = result.NewPhase
315→
316→	var handlerErr error
317→	for _, action := range result.Actions {
318→		switch action {
319→		// Common actions: always applied, even after a handler error.
320→		case ActionUpdateLastInteraction:
321→			now := time.Now()
322→			state.LastInteractionTime = &now
323→		case ActionClearEndedAt:
324→			state.EndedAt = nil
325→
326→		// Strategy-specific actions: skip remaining after the first handler error.
327→		case ActionCondense:
328→			if handlerErr == nil {
329→				if err := handler.HandleCondense(state); err != nil {
330→					handlerErr = fmt.Errorf("%s: %w", action, err)
331→				}
332→			}
333→		case ActionCondenseIfFilesTouched:
334→			if handlerErr == nil {
335→				if err := handler.HandleCondenseIfFilesTouched(state); err != nil {
336→					handlerErr = fmt.Errorf("%s: %w", action, err)
337→				}
338→			}
339→		case ActionDiscardIfNoFiles:
340→			if handlerErr == nil {
341→				if err := handler.HandleDiscardIfNoFiles(state); err != nil {
342→					handlerErr = fmt.Errorf("%s: %w", action, err)
343→				}
344→			}
345→		case ActionWarnStaleSession:
346→			if handlerErr == nil {
347→				if err := handler.HandleWarnStaleSession(state); err != nil {
348→					handlerErr = fmt.Errorf("%s: %w", action, err)
349→				}
350→			}
351→		default:
352→			if handlerErr == nil {
353→				handlerErr = fmt.Errorf("unhandled action: %s", action)
354→			}
355→		}
356→	}
357→	return handlerErr
358→}
359→
360→// MermaidDiagram generates a Mermaid state diagram from the transition table.
361→// The diagram is derived by calling Transition() for representative context
362→// variants per phase/event, so it stays in sync with the implementation.
363→func MermaidDiagram() string {
364→	var b strings.Builder
365→	b.WriteString("stateDiagram-v2\n")
366→
367→	// State declarations with descriptions.
368→	b.WriteString("    state \"IDLE\" as idle\n")
369→	b.WriteString("    state \"ACTIVE\" as active\n")
370→	b.WriteString("    state \"ENDED\" as ended\n")
371→	b.WriteString("\n")
372→
373→	// Context variants for GitCommit: rebase, files/no-files.
374→	type contextVariant struct {
375→		label string
376→		ctx   TransitionContext
377→	}
378→
379→	// For each phase/event, generate edges.
380→	for _, phase := range allPhases {
381→		for _, event := range allEvents {
382→			var variants []contextVariant
383→			switch {
384→			case event == EventGitCommit && phase == PhaseEnded:
385→				// HasFilesTouched only affects PhaseEnded transitions;
386→				// other phases produce identical edges for both values.
387→				variants = []contextVariant{
388→					{"[files]", TransitionContext{HasFilesTouched: true}},
389→					{"[no files]", TransitionContext{HasFilesTouched: false}},
390→					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
391→				}
392→			case event == EventGitCommit:
393→				variants = []contextVariant{
394→					{"", TransitionContext{}},
395→					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
396→				}
397→			default:
398→				variants = []contextVariant{
399→					{"", TransitionContext{}},
400→				}
401→			}
402→
403→			for _, v := range variants {
404→				result := Transition(phase, event, v.ctx)
405→
406→				// Build edge label.
407→				label := event.String()
408→				if v.label != "" {
409→					label += " " + v.label
410→				}
411→				if len(result.Actions) > 0 {
412→					actionNames := make([]string, 0, len(result.Actions))
413→					for _, a := range result.Actions {
414→						actionNames = append(actionNames, a.String())
415→					}
416→					label += " / " + strings.Join(actionNames, ", ")
417→				}
418→
419→				from := string(phase)
420→				to := string(result.NewPhase)
421→
422→				fmt.Fprintf(&b, "    %s --> %s : %s\n", from, to, label)
423→			}
424→		}
425→	}
426→
427→	return b.String()
428→}
