389→// CapturePreTaskState captures current untracked files before a Task execution
390→// and saves them to a state file.
391→// Works correctly from any subdirectory within the repository.
392→func CapturePreTaskState(toolUseID string) error {
393→	if toolUseID == "" {
394→		return errors.New("tool_use_id is required")
395→	}
396→
397→	// Get absolute path for tmp directory
398→	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
399→	if err != nil {
400→		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
401→	}
402→
403→	// Create tmp directory if it doesn't exist
404→	if err := os.MkdirAll(tmpDirAbs, 0o750); err != nil {
405→		return fmt.Errorf("failed to create tmp directory: %w", err)
406→	}
407→
408→	// Get list of untracked files (excluding .entire directory itself)
409→	untrackedFiles, err := getUntrackedFilesForState()
410→	if err != nil {
411→		return fmt.Errorf("failed to get untracked files: %w", err)
412→	}
413→
414→	// Create state file
415→	stateFile := preTaskStateFile(toolUseID)
416→	state := PreTaskState{
417→		ToolUseID:      toolUseID,
418→		Timestamp:      time.Now().UTC().Format(time.RFC3339),
419→		UntrackedFiles: untrackedFiles,
420→	}
421→
422→	data, err := jsonutil.MarshalIndentWithNewline(state, "", "  ")
423→	if err != nil {
424→		return fmt.Errorf("failed to marshal state: %w", err)
425→	}
426→
427→	if err := os.WriteFile(stateFile, data, 0o600); err != nil {
428→		return fmt.Errorf("failed to write state file: %w", err)
429→	}
430→
431→	fmt.Fprintf(os.Stderr, "Captured state before task: %d untracked files\n", len(untrackedFiles))
432→	return nil
433→}
