163→func TestFilterAndNormalizePaths_SiblingDirectories(t *testing.T) {
164→	// This test verifies the fix for the bug where files in sibling directories
165→	// were filtered out when Claude runs from a subdirectory.
166→	// When Claude is in /repo/frontend and edits /repo/api/file.ts,
167→	// the relative path would be ../api/file.ts which was incorrectly filtered.
168→	// The fix uses repo root instead of cwd, so paths should be api/file.ts.
169→
170→	tests := []struct {
171→		name     string
172→		files    []string
173→		basePath string // simulates repo root or cwd
174→		want     []string
175→	}{
176→		{
177→			name: "files in sibling directories with repo root base",
178→			files: []string{
179→				"/repo/api/src/lib/github.ts",
180→				"/repo/api/src/types.ts",
181→				"/repo/frontend/src/pages/api.ts",
182→			},
183→			basePath: "/repo", // repo root
184→			want: []string{
185→				"api/src/lib/github.ts",
186→				"api/src/types.ts",
187→				"frontend/src/pages/api.ts",
188→			},
189→		},
190→		{
191→			name: "files in sibling directories with subdirectory base (old buggy behavior)",
192→			files: []string{
193→				"/repo/api/src/lib/github.ts",
194→				"/repo/frontend/src/pages/api.ts",
195→			},
196→			basePath: "/repo/frontend", // cwd in subdirectory
197→			want: []string{
198→				// Only frontend file should remain, api file gets filtered
199→				// because ../api/... starts with ..
200→				"src/pages/api.ts",
201→			},
202→		},
203→		{
204→			name: "relative paths pass through unchanged",
205→			files: []string{
206→				"src/file.ts",
207→				"lib/util.go",
208→			},
209→			basePath: "/repo",
210→			want: []string{
211→				"src/file.ts",
212→				"lib/util.go",
213→			},
214→		},
215→		{
216→			name: "infrastructure paths are filtered",
217→			files: []string{
218→				"/repo/src/file.ts",
219→				"/repo/.entire/metadata/session.json",
220→			},
221→			basePath: "/repo",
222→			want: []string{
223→				"src/file.ts",
224→				// .entire path should be filtered
225→			},
226→		},
227→	}
228→
229→	for _, tt := range tests {
230→		t.Run(tt.name, func(t *testing.T) {
231→			got := FilterAndNormalizePaths(tt.files, tt.basePath)
232→			if len(got) != len(tt.want) {
233→				t.Errorf("FilterAndNormalizePaths() returned %d files, want %d\ngot: %v\nwant: %v",
234→					len(got), len(tt.want), got, tt.want)
235→				return
236→			}
237→			for i, want := range tt.want {
238→				if got[i] != want {
239→					t.Errorf("FilterAndNormalizePaths()[%d] = %v, want %v", i, got[i], want)
240→				}
241→			}
242→		})
243→	}
244→}
