248→// filterToUncommittedFiles removes files from the list that are already committed to HEAD
249→// with matching content. This prevents re-adding files that an agent committed mid-turn
250→// (already condensed by PostCommit) back to FilesTouched via SaveChanges. Files not in
251→// HEAD or with different content in the working tree are kept. Fails open: if any git
252→// operation errors, returns the original list unchanged.
253→func filterToUncommittedFiles(files []string, repoRoot string) []string {
254→	if len(files) == 0 {
255→		return files
256→	}
257→
258→	repo, err := openRepository()
259→	if err != nil {
260→		return files // fail open
261→	}
262→
263→	head, err := repo.Head()
264→	if err != nil {
265→		return files // fail open (empty repo, detached HEAD, etc.)
266→	}
267→
268→	commit, err := repo.CommitObject(head.Hash())
269→	if err != nil {
270→		return files // fail open
271→	}
272→
273→	headTree, err := commit.Tree()
274→	if err != nil {
275→		return files // fail open
276→	}
277→
278→	var result []string
279→	for _, relPath := range files {
280→		headFile, err := headTree.File(relPath)
281→		if err != nil {
282→			// File not in HEAD — it's uncommitted
283→			result = append(result, relPath)
284→			continue
285→		}
286→
287→		// File is in HEAD — compare content with working tree
288→		absPath := filepath.Join(repoRoot, relPath)
289→		workingContent, err := os.ReadFile(absPath) //nolint:gosec // path from controlled source
290→		if err != nil {
291→			// Can't read working tree file (deleted?) — keep it
292→			result = append(result, relPath)
293→			continue
294→		}
295→
296→		headContent, err := headFile.Contents()
297→		if err != nil {
298→			result = append(result, relPath)
299→			continue
300→		}
301→
302→		if string(workingContent) != headContent {
303→			// Working tree differs from HEAD — uncommitted changes
304→			result = append(result, relPath)
305→		}
306→		// else: content matches HEAD — already committed, skip
307→	}
308→
309→	return result
310→}
