476→// preTaskFilePrefix is the prefix for pre-task state files
477→const preTaskFilePrefix = "pre-task-"
478→
479→// FindActivePreTaskFile finds an active pre-task file in .entire/tmp/ and returns
480→// the parent Task's tool_use_id. Returns ("", false) if no pre-task file exists.
481→// When multiple pre-task files exist (nested subagents), returns the most recently
482→// modified one.
483→// Works correctly from any subdirectory within the repository.
484→func FindActivePreTaskFile() (taskToolUseID string, found bool) {
485→	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
486→	if err != nil {
487→		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
488→	}
489→	entries, err := os.ReadDir(tmpDirAbs)
490→	if err != nil {
491→		return "", false
492→	}
493→
494→	var latestFile string
495→	var latestTime time.Time
496→
497→	for _, entry := range entries {
498→		if entry.IsDir() {
499→			continue
500→		}
501→		name := entry.Name()
502→		if !strings.HasPrefix(name, preTaskFilePrefix) || !strings.HasSuffix(name, ".json") {
503→			continue
504→		}
505→
506→		// Check modification time for nested subagent handling
507→		info, err := entry.Info()
508→		if err != nil {
509→			continue
510→		}
511→		if latestFile == "" || info.ModTime().After(latestTime) {
512→			latestFile = name
513→			latestTime = info.ModTime()
514→		}
515→	}
516→
517→	if latestFile == "" {
518→		return "", false
519→	}
520→
521→	// Extract tool_use_id from filename: pre-task-<tool_use_id>.json
522→	toolUseID := strings.TrimPrefix(latestFile, preTaskFilePrefix)
523→	toolUseID = strings.TrimSuffix(toolUseID, ".json")
524→	return toolUseID, true
525→}
