527→// GetNextCheckpointSequence returns the next sequence number for incremental checkpoints.
528→// It counts existing checkpoint files in the task metadata checkpoints directory.
529→// Returns 1 if no checkpoints exist yet.
530→func GetNextCheckpointSequence(sessionID, taskToolUseID string) int {
531→	// Use the session ID directly as the metadata directory name
532→	sessionMetadataDir := paths.SessionMetadataDirFromSessionID(sessionID)
533→	taskMetadataDir := strategy.TaskMetadataDir(sessionMetadataDir, taskToolUseID)
534→	checkpointsDir := filepath.Join(taskMetadataDir, "checkpoints")
535→
536→	entries, err := os.ReadDir(checkpointsDir)
537→	if err != nil {
538→		// Directory doesn't exist or can't be read - start at 1
539→		return 1
540→	}
541→
542→	// Count JSON files (checkpoints)
543→	count := 0
544→	for _, entry := range entries {
545→		if !entry.IsDir() && strings.HasSuffix(entry.Name(), ".json") {
546→			count++
547→		}
548→	}
549→
550→	return count + 1
551→}
