381→// ExtractModifiedFilesFromOffset extracts files modified since a given line number.
382→// For Claude Code (JSONL format), offset is the starting line number.
383→// Uses bufio.Reader to handle arbitrarily long lines (no size limit).
384→// Returns:
385→//   - files: list of file paths modified by Claude (from Write/Edit tools)
386→//   - currentPosition: total number of lines in the file
387→//   - error: any error encountered during reading
388→func (c *ClaudeCodeAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
389→	if path == "" {
390→		return nil, 0, nil
391→	}
392→
393→	file, openErr := os.Open(path) //nolint:gosec // Path comes from Claude Code transcript location
394→	if openErr != nil {
395→		return nil, 0, fmt.Errorf("failed to open transcript file: %w", openErr)
396→	}
397→	defer file.Close()
398→
399→	reader := bufio.NewReader(file)
400→	var lines []TranscriptLine
401→	lineNum := 0
402→
403→	for {
404→		lineData, readErr := reader.ReadBytes('\n')
405→		if readErr != nil && readErr != io.EOF {
406→			return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
407→		}
408→
409→		if len(lineData) > 0 {
410→			lineNum++
411→			if lineNum > startOffset {
412→				var line TranscriptLine
413→				if parseErr := json.Unmarshal(lineData, &line); parseErr == nil {
414→					lines = append(lines, line)
415→				}
416→				// Skip malformed lines silently
417→			}
418→		}
419→
420→		if readErr == io.EOF {
421→			break
422→		}
423→	}
424→
425→	return ExtractModifiedFiles(lines), lineNum, nil
426→}
