150→// handleLifecycleTurnEnd handles turn end: validates transcript, extracts metadata,
151→// detects file changes, saves step + checkpoint, transitions phase.
152→//
153→//nolint:maintidx // high complexity due to sequential orchestration of 8 steps (validation, extraction, file detection, filtering, token calc, step save, phase transition, cleanup) - splitting would obscure the flow
154→func handleLifecycleTurnEnd(ag agent.Agent, event *agent.Event) error {
155→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
156→	logging.Info(logCtx, "turn-end",
157→		slog.String("event", event.Type.String()),
158→		slog.String("session_id", event.SessionID),
159→		slog.String("session_ref", event.SessionRef),
160→	)
161→
162→	sessionID := event.SessionID
163→	if sessionID == "" {
164→		sessionID = unknownSessionID
165→	}
166→
167→	transcriptRef := event.SessionRef
168→	if transcriptRef == "" {
169→		return errors.New("transcript file not specified")
170→	}
171→	if !fileExists(transcriptRef) {
172→		return fmt.Errorf("transcript file not found: %s", transcriptRef)
173→	}
174→
175→	// Early check: bail out quickly if the repo has no commits yet.
176→	if repo, err := strategy.OpenRepository(); err == nil && strategy.IsEmptyRepository(repo) {
177→		fmt.Fprintln(os.Stderr, "Entire: skipping checkpoint. Will activate after first commit.")
178→		return NewSilentError(strategy.ErrEmptyRepository)
179→	}
180→
181→	// Create session metadata directory
182→	sessionDir := paths.SessionMetadataDirFromSessionID(sessionID)
183→	sessionDirAbs, err := paths.AbsPath(sessionDir)
184→	if err != nil {
185→		sessionDirAbs = sessionDir
186→	}
187→	if err := os.MkdirAll(sessionDirAbs, 0o750); err != nil {
188→		return fmt.Errorf("failed to create session directory: %w", err)
189→	}
190→
191→	// If agent implements TranscriptPreparer, wait for transcript to be ready
192→	if preparer, ok := ag.(agent.TranscriptPreparer); ok {
193→		if err := preparer.PrepareTranscript(transcriptRef); err != nil {
194→			fmt.Fprintf(os.Stderr, "Warning: failed to prepare transcript: %v\n", err)
195→		}
196→	}
197→
198→	// Copy transcript to session directory
199→	transcriptData, err := ag.ReadTranscript(transcriptRef)
200→	if err != nil {
201→		return fmt.Errorf("failed to read transcript: %w", err)
202→	}
203→	logFile := filepath.Join(sessionDirAbs, paths.TranscriptFileName)
204→	if err := os.WriteFile(logFile, transcriptData, 0o600); err != nil {
205→		return fmt.Errorf("failed to write transcript: %w", err)
206→	}
207→	fmt.Fprintf(os.Stderr, "Copied transcript to: %s\n", sessionDir+"/"+paths.TranscriptFileName)
208→
209→	// Load pre-prompt state (captured on TurnStart)
210→	preState, err := LoadPrePromptState(sessionID)
211→	if err != nil {
212→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-prompt state: %v\n", err)
213→	}
214→
215→	// Determine transcript offset
216→	transcriptOffset := resolveTranscriptOffset(preState, sessionID)
217→
218→	// Extract metadata via agent interface (prompts, summary, modified files)
219→	var allPrompts []string
220→	var summary string
221→	var modifiedFiles []string
222→	var newTranscriptPosition int
223→
224→	// Compute subagents directory for agents that support subagent extraction.
225→	// Subagent transcripts live in <transcriptDir>/<modelSessionID>/subagents/
226→	subagentsDir := filepath.Join(filepath.Dir(transcriptRef), event.SessionID, "subagents")
227→
228→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
229→		// Extract prompts
230→		if prompts, promptErr := analyzer.ExtractPrompts(transcriptRef, transcriptOffset); promptErr != nil {
231→			fmt.Fprintf(os.Stderr, "Warning: failed to extract prompts: %v\n", promptErr)
232→		} else {
233→			allPrompts = prompts
234→		}
235→
236→		// Extract summary
237→		if s, sumErr := analyzer.ExtractSummary(transcriptRef); sumErr != nil {
238→			fmt.Fprintf(os.Stderr, "Warning: failed to extract summary: %v\n", sumErr)
239→		} else {
240→			summary = s
241→		}
242→
243→		// Extract modified files - prefer SubagentAwareExtractor if available to include subagent files
244→		if subagentExtractor, subOk := ag.(agent.SubagentAwareExtractor); subOk {
245→			if files, fileErr := subagentExtractor.ExtractAllModifiedFiles(transcriptRef, transcriptOffset, subagentsDir); fileErr != nil {
246→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files (with subagents): %v\n", fileErr)
247→			} else {
248→				modifiedFiles = files
249→			}
250→			// Get position from basic analyzer
251→			if _, pos, posErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); posErr == nil {
252→				newTranscriptPosition = pos
253→			}
254→		} else {
255→			// Fall back to basic extraction (main transcript only)
256→			if files, pos, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); fileErr != nil {
257→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files: %v\n", fileErr)
258→			} else {
259→				modifiedFiles = files
260→				newTranscriptPosition = pos
261→			}
262→		}
263→	}
264→
265→	// Write prompts file
266→	promptFile := filepath.Join(sessionDirAbs, paths.PromptFileName)
267→	promptContent := strings.Join(allPrompts, "\n\n---\n\n")
268→	if err := os.WriteFile(promptFile, []byte(promptContent), 0o600); err != nil {
269→		return fmt.Errorf("failed to write prompt file: %w", err)
270→	}
271→	fmt.Fprintf(os.Stderr, "Extracted %d prompt(s) to: %s\n", len(allPrompts), sessionDir+"/"+paths.PromptFileName)
272→
273→	// Write summary file
274→	summaryFile := filepath.Join(sessionDirAbs, paths.SummaryFileName)
275→	if err := os.WriteFile(summaryFile, []byte(summary), 0o600); err != nil {
276→		return fmt.Errorf("failed to write summary file: %w", err)
277→	}
278→	fmt.Fprintf(os.Stderr, "Extracted summary to: %s\n", sessionDir+"/"+paths.SummaryFileName)
279→
280→	// Generate commit message from last prompt
281→	lastPrompt := ""
282→	if len(allPrompts) > 0 {
283→		lastPrompt = allPrompts[len(allPrompts)-1]
284→	}
285→	commitMessage := generateCommitMessage(lastPrompt)
286→	fmt.Fprintf(os.Stderr, "Using commit message: %s\n", commitMessage)
287→
288→	// Get repo root for path normalization
289→	repoRoot, err := paths.RepoRoot()
290→	if err != nil {
291→		return fmt.Errorf("failed to get repo root: %w", err)
292→	}
293→
294→	var preUntrackedFiles []string
295→	if preState != nil {
296→		fmt.Fprintf(os.Stderr, "Pre-prompt state: %d pre-existing untracked files\n", len(preState.UntrackedFiles))
297→		preUntrackedFiles = preState.PreUntrackedFiles()
298→	}
299→
300→	// Detect file changes via git status
301→	changes, err := DetectFileChanges(preUntrackedFiles)
302→	if err != nil {
303→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
304→	}
305→
306→	// Filter and normalize all paths
307→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
308→	var relNewFiles, relDeletedFiles []string
309→	if changes != nil {
310→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
311→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
312→	}
313→
314→	// Filter transcript-extracted files to exclude files already committed to HEAD.
315→	// When an agent commits files mid-turn, those files are condensed by PostCommit
316→	// and should not be re-added to FilesTouched by SaveStep. A file is "committed"
317→	// if it exists in HEAD with the same content as the working tree.
318→	relModifiedFiles = filterToUncommittedFiles(relModifiedFiles, repoRoot)
319→
320→	// Check if there are any changes
321→	totalChanges := len(relModifiedFiles) + len(relNewFiles) + len(relDeletedFiles)
322→	if totalChanges == 0 {
323→		fmt.Fprintf(os.Stderr, "No files were modified during this session\n")
324→		fmt.Fprintf(os.Stderr, "Skipping commit\n")
325→		transitionSessionTurnEnd(sessionID)
326→		if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
327→			fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
328→		}
329→		return nil
330→	}
331→
332→	// Log file changes
333→	logFileChanges(relModifiedFiles, relNewFiles, relDeletedFiles)
334→
335→	// Create context file
336→	contextFile := filepath.Join(sessionDirAbs, paths.ContextFileName)
337→	if err := createContextFile(contextFile, commitMessage, sessionID, allPrompts, summary); err != nil {
338→		return fmt.Errorf("failed to create context file: %w", err)
339→	}
340→	fmt.Fprintf(os.Stderr, "Created context file: %s\n", sessionDir+"/"+paths.ContextFileName)
341→
342→	// Get git author
343→	author, err := GetGitAuthor()
344→	if err != nil {
345→		return fmt.Errorf("failed to get git author: %w", err)
346→	}
347→
348→	// Get strategy and agent type
349→	strat := GetStrategy()
350→	agentType := ag.Type()
351→
352→	// Get transcript position/identifier from pre-prompt state
353→	var transcriptIdentifierAtStart string
354→	var transcriptLinesAtStart int
355→	if preState != nil {
356→		transcriptIdentifierAtStart = preState.LastTranscriptIdentifier
357→		transcriptLinesAtStart = preState.TranscriptOffset
358→	}
359→
360→	// Calculate token usage - prefer SubagentAwareExtractor to include subagent tokens
361→	var tokenUsage *agent.TokenUsage
362→	if subagentExtractor, ok := ag.(agent.SubagentAwareExtractor); ok {
363→		usage, tokenErr := subagentExtractor.CalculateTotalTokenUsage(transcriptRef, transcriptLinesAtStart, subagentsDir)
364→		if tokenErr != nil {
365→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage (with subagents): %v\n", tokenErr)
366→		} else {
367→			tokenUsage = usage
368→		}
369→	} else if calculator, ok := ag.(agent.TokenCalculator); ok {
370→		// Fall back to basic token calculation (main transcript only)
371→		usage, tokenErr := calculator.CalculateTokenUsage(transcriptRef, transcriptLinesAtStart)
372→		if tokenErr != nil {
373→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage: %v\n", tokenErr)
374→		} else {
375→			tokenUsage = usage
376→		}
377→	}
378→
379→	// Build fully-populated step context and delegate to strategy
380→	ctx := strategy.StepContext{
381→		SessionID:                sessionID,
382→		ModifiedFiles:            relModifiedFiles,
383→		NewFiles:                 relNewFiles,
384→		DeletedFiles:             relDeletedFiles,
385→		MetadataDir:              sessionDir,
386→		MetadataDirAbs:           sessionDirAbs,
387→		CommitMessage:            commitMessage,
388→		TranscriptPath:           transcriptRef,
389→		AuthorName:               author.Name,
390→		AuthorEmail:              author.Email,
391→		AgentType:                agentType,
392→		StepTranscriptIdentifier: transcriptIdentifierAtStart,
393→		StepTranscriptStart:      transcriptLinesAtStart,
394→		TokenUsage:               tokenUsage,
395→	}
396→
397→	if err := strat.SaveStep(ctx); err != nil {
398→		return fmt.Errorf("failed to save step: %w", err)
399→	}
400→
401→	// Update session state transcript position for auto-commit strategy
402→	if strat.Name() == strategy.StrategyNameAutoCommit && newTranscriptPosition > 0 {
403→		updateAutoCommitTranscriptPosition(sessionID, newTranscriptPosition)
404→	}
405→
406→	// Transition session phase and cleanup
407→	transitionSessionTurnEnd(sessionID)
408→	if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
409→		fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
410→	}
411→
412→	return nil
413→}
