415→// handleLifecycleCompaction handles context compaction: saves current progress
416→// but stays in ACTIVE phase (unlike TurnEnd which transitions to IDLE).
417→// Also resets the transcript offset since the transcript may be truncated.
418→func handleLifecycleCompaction(ag agent.Agent, event *agent.Event) error {
419→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
420→	logging.Info(logCtx, "compaction",
421→		slog.String("event", event.Type.String()),
422→		slog.String("session_id", event.SessionID),
423→	)
424→
425→	// Fire EventCompaction to trigger ActionCondenseIfFilesTouched (stays in ACTIVE)
426→	sessionID := event.SessionID
427→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
428→	if loadErr != nil {
429→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for compaction: %v\n", loadErr)
430→	}
431→	if sessionState != nil {
432→		if transErr := strategy.TransitionAndLog(sessionState, session.EventCompaction, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
433→			fmt.Fprintf(os.Stderr, "Warning: compaction transition failed: %v\n", transErr)
434→		}
435→
436→		// Reset transcript offset since the transcript may be truncated/reorganized
437→		sessionState.CheckpointTranscriptStart = 0
438→
439→		if saveErr := strategy.SaveSessionState(sessionState); saveErr != nil {
440→			fmt.Fprintf(os.Stderr, "Warning: failed to save session state after compaction: %v\n", saveErr)
441→		}
442→	}
443→
444→	fmt.Fprintf(os.Stderr, "Context compaction: transcript offset reset\n")
445→	return nil
446→}
