489→// handleLifecycleSubagentEnd handles subagent end: detects changes, saves task checkpoint.
490→func handleLifecycleSubagentEnd(ag agent.Agent, event *agent.Event) error {
491→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
492→	logging.Info(logCtx, "subagent-end",
493→		slog.String("event", event.Type.String()),
494→		slog.String("session_id", event.SessionID),
495→		slog.String("tool_use_id", event.ToolUseID),
496→		slog.String("subagent_id", event.SubagentID),
497→	)
498→
499→	// Extract subagent type and description from tool input
500→	subagentType, taskDescription := ParseSubagentTypeAndDescription(event.ToolInput)
501→
502→	// Determine subagent transcript path
503→	transcriptDir := filepath.Dir(event.SessionRef)
504→	var subagentTranscriptPath string
505→	if event.SubagentID != "" {
506→		subagentTranscriptPath = AgentTranscriptPath(transcriptDir, event.SubagentID)
507→		if !fileExists(subagentTranscriptPath) {
508→			subagentTranscriptPath = ""
509→		}
510→	}
511→
512→	// Log context
513→	fmt.Fprintf(os.Stderr, "[entire] Subagent completed\n")
514→	fmt.Fprintf(os.Stderr, "  Session ID: %s\n", event.SessionID)
515→	fmt.Fprintf(os.Stderr, "  Tool Use ID: %s\n", event.ToolUseID)
516→	if event.SubagentID != "" {
517→		fmt.Fprintf(os.Stderr, "  Agent ID: %s\n", event.SubagentID)
518→	}
519→	if subagentTranscriptPath != "" {
520→		fmt.Fprintf(os.Stderr, "  Subagent Transcript: %s\n", subagentTranscriptPath)
521→	}
522→
523→	// Extract modified files from subagent transcript
524→	var modifiedFiles []string
525→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
526→		transcriptToScan := event.SessionRef
527→		if subagentTranscriptPath != "" {
528→			transcriptToScan = subagentTranscriptPath
529→		}
530→		if files, _, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptToScan, 0); fileErr != nil {
531→			fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files from subagent: %v\n", fileErr)
532→		} else {
533→			modifiedFiles = files
534→		}
535→	}
536→
537→	// Load pre-task state and detect file changes
538→	preState, err := LoadPreTaskState(event.ToolUseID)
539→	if err != nil {
540→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-task state: %v\n", err)
541→	}
542→	changes, err := DetectFileChanges(preState.PreUntrackedFiles())
543→	if err != nil {
544→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
545→	}
546→
547→	// Get repo root and normalize paths
548→	repoRoot, err := paths.RepoRoot()
549→	if err != nil {
550→		return fmt.Errorf("failed to get repo root: %w", err)
551→	}
552→
553→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
554→	var relNewFiles, relDeletedFiles []string
555→	if changes != nil {
556→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
557→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
558→	}
559→
560→	// If no changes, skip
561→	if len(relModifiedFiles) == 0 && len(relNewFiles) == 0 && len(relDeletedFiles) == 0 {
562→		fmt.Fprintf(os.Stderr, "[entire] No file changes detected, skipping task checkpoint\n")
563→		_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
564→		return nil
565→	}
566→
567→	// Find checkpoint UUID from main transcript (best-effort)
568→	var checkpointUUID string
569→	// Use the existing CLI-level checkpoint UUID finder
570→	mainLines, _, _ := parseTranscriptForCheckpointUUID(event.SessionRef) //nolint:errcheck // best-effort
571→	if mainLines != nil {
572→		checkpointUUID, _ = FindCheckpointUUID(mainLines, event.ToolUseID)
573→	}
574→
575→	// Get git author
576→	author, err := GetGitAuthor()
577→	if err != nil {
578→		return fmt.Errorf("failed to get git author: %w", err)
579→	}
580→
581→	// Build task checkpoint context
582→	strat := GetStrategy()
583→	agentType := ag.Type()
584→
585→	ctx := strategy.TaskStepContext{
586→		SessionID:              event.SessionID,
587→		ToolUseID:              event.ToolUseID,
588→		AgentID:                event.SubagentID,
589→		ModifiedFiles:          relModifiedFiles,
590→		NewFiles:               relNewFiles,
591→		DeletedFiles:           relDeletedFiles,
592→		TranscriptPath:         event.SessionRef,
593→		SubagentTranscriptPath: subagentTranscriptPath,
594→		CheckpointUUID:         checkpointUUID,
595→		AuthorName:             author.Name,
596→		AuthorEmail:            author.Email,
597→		SubagentType:           subagentType,
598→		TaskDescription:        taskDescription,
599→		AgentType:              agentType,
600→	}
601→
602→	if err := strat.SaveTaskStep(ctx); err != nil {
603→		return fmt.Errorf("failed to save task step: %w", err)
604→	}
605→
606→	_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
607→	return nil
608→}
