657→// createContextFile creates a context.md file for the session checkpoint.
658→// This is a unified version that works for all agents.
659→func createContextFile(contextFile, commitMessage, sessionID string, prompts []string, summary string) error {
660→	var sb strings.Builder
661→
662→	sb.WriteString("# Session Context\n\n")
663→	sb.WriteString(fmt.Sprintf("Session ID: %s\n", sessionID))
664→	sb.WriteString(fmt.Sprintf("Commit Message: %s\n\n", commitMessage))
665→
666→	if len(prompts) > 0 {
667→		sb.WriteString("## Prompts\n\n")
668→		for i, p := range prompts {
669→			sb.WriteString(fmt.Sprintf("### Prompt %d\n\n%s\n\n", i+1, p))
670→		}
671→	}
672→
673→	if summary != "" {
674→		sb.WriteString("## Summary\n\n")
675→		sb.WriteString(summary)
676→		sb.WriteString("\n")
677→	}
678→
679→	if err := os.WriteFile(contextFile, []byte(sb.String()), 0o600); err != nil {
680→		return fmt.Errorf("failed to write context file: %w", err)
681→	}
682→	return nil
683→}
