685→// parseTranscriptForCheckpointUUID is a thin wrapper around transcript parsing for checkpoint UUID lookup.
686→// Returns parsed transcript lines for use with FindCheckpointUUID.
687→func parseTranscriptForCheckpointUUID(transcriptPath string) ([]transcriptLine, int, error) {
688→	lines, total, err := transcript.ParseFromFileAtLine(transcriptPath, 0)
689→	if err != nil {
690→		return nil, 0, fmt.Errorf("parsing transcript for checkpoint UUID: %w", err)
691→	}
692→	return lines, total, nil
693→}
