746→// logFileChanges logs the files modified, created, and deleted during a session.
747→func logFileChanges(modified, newFiles, deleted []string) {
748→	fmt.Fprintf(os.Stderr, "Files modified during session (%d):\n", len(modified))
749→	for _, file := range modified {
750→		fmt.Fprintf(os.Stderr, "  - %s\n", file)
751→	}
752→	if len(newFiles) > 0 {
753→		fmt.Fprintf(os.Stderr, "New files created (%d):\n", len(newFiles))
754→		for _, file := range newFiles {
755→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
756→		}
757→	}
758→	if len(deleted) > 0 {
759→		fmt.Fprintf(os.Stderr, "Files deleted (%d):\n", len(deleted))
760→		for _, file := range deleted {
761→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
762→		}
763→	}
764→}
