162→// ResolveSessionFile returns the path to a Gemini session file.
163→// Gemini names files as session-<date>-<shortid>.json where shortid is the first 8 chars
164→// of the session UUID. This searches for an existing file matching the pattern, falling
165→// back to <dir>/<id>.json if no match is found.
166→func (g *GeminiCLIAgent) ResolveSessionFile(sessionDir, agentSessionID string) string {
167→	// Try to find existing file matching Gemini's naming convention:
168→	// session-*-<first8chars>.json
169→	shortID := agentSessionID
170→	if len(shortID) > 8 {
171→		shortID = shortID[:8]
172→	}
173→
174→	pattern := filepath.Join(sessionDir, "session-*-"+shortID+".json")
175→	matches, err := filepath.Glob(pattern)
176→	if err == nil && len(matches) > 0 {
177→		// Return the most recent match (last alphabetically, since date is in the name)
178→		return matches[len(matches)-1]
179→	}
180→
181→	// Fallback: construct a default path
182→	return filepath.Join(sessionDir, agentSessionID+".json")
183→}
