612→// resolveTranscriptOffset determines the transcript offset to use for parsing.
613→// Prefers pre-prompt state, falls back to session state.
614→func resolveTranscriptOffset(preState *PrePromptState, sessionID string) int {
615→	if preState != nil && preState.TranscriptOffset > 0 {
616→		fmt.Fprintf(os.Stderr, "Pre-prompt state found: parsing transcript from offset %d\n", preState.TranscriptOffset)
617→		return preState.TranscriptOffset
618→	}
619→
620→	// Fall back to session state (e.g., auto-commit strategy updates it after each save)
621→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
622→	if loadErr != nil {
623→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
624→		return 0
625→	}
626→	if sessionState != nil && sessionState.CheckpointTranscriptStart > 0 {
627→		fmt.Fprintf(os.Stderr, "Session state found: parsing transcript from offset %d\n", sessionState.CheckpointTranscriptStart)
628→		return sessionState.CheckpointTranscriptStart
629→	}
630→
631→	return 0
632→}
