695→// transitionSessionTurnEnd transitions the session phase to IDLE and dispatches turn-end actions.
696→func transitionSessionTurnEnd(sessionID string) {
697→	turnState, loadErr := strategy.LoadSessionState(sessionID)
698→	if loadErr != nil {
699→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for turn end: %v\n", loadErr)
700→		return
701→	}
702→	if turnState == nil {
703→		return
704→	}
705→	if err := strategy.TransitionAndLog(turnState, session.EventTurnEnd, session.TransitionContext{}, session.NoOpActionHandler{}); err != nil {
706→		fmt.Fprintf(os.Stderr, "Warning: turn-end transition failed: %v\n", err)
707→	}
708→
709→	// Always dispatch to strategy for turn-end handling. The strategy reads
710→	// work items from state (e.g. TurnCheckpointIDs), not the action list.
711→	strat := GetStrategy()
712→	if handler, ok := strat.(strategy.TurnEndHandler); ok {
713→		if err := handler.HandleTurnEnd(turnState); err != nil {
714→			fmt.Fprintf(os.Stderr, "Warning: turn-end action dispatch failed: %v\n", err)
715→		}
716→	}
717→
718→	if updateErr := strategy.SaveSessionState(turnState); updateErr != nil {
719→		fmt.Fprintf(os.Stderr, "Warning: failed to update session phase on turn end: %v\n", updateErr)
720→	}
721→}
