723→// markSessionEnded transitions the session to ENDED phase via the state machine.
724→func markSessionEnded(sessionID string) error {
725→	state, err := strategy.LoadSessionState(sessionID)
726→	if err != nil {
727→		return fmt.Errorf("failed to load session state: %w", err)
728→	}
729→	if state == nil {
730→		return nil // No state file, nothing to update
731→	}
732→
733→	if transErr := strategy.TransitionAndLog(state, session.EventSessionStop, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
734→		fmt.Fprintf(os.Stderr, "Warning: session stop transition failed: %v\n", transErr)
735→	}
736→
737→	now := time.Now()
738→	state.EndedAt = &now
739→
740→	if err := strategy.SaveSessionState(state); err != nil {
741→		return fmt.Errorf("failed to save session state: %w", err)
742→	}
743→	return nil
744→}
