	committedFiles := map[string]struct{}{"src/app.go": {}, "docs/notes.md": {}}
	result, err := s.CondenseSession(repo, checkpointID, state, committedFiles)
	if err != nil {
		t.Fatalf("CondenseSession() error = %v", err)
	}
