		t.Errorf("CheckpointID = %q, want %q", result.CheckpointID, checkpointID)
	}

	// Read metadata
	sessionsRef, err := repo.Reference(plumbing.NewBranchReferenceName(paths.MetadataBranchName), true)
	if err != nil {
		t.Fatalf("failed to get sessions branch: %v", err)
	}
